"use client";

import { useEffect, useRef, useState } from "react";
import Link from "next/link";
import { usePathname, useRouter, useSearchParams } from "next/navigation";
import { DataTable, ColumnDef } from "@/components/ui/DataTable";
import {
    AlertCircle,
    User as UserIcon,
    Mail,
} from "lucide-react";
import { AdminModuleTabs } from "@/components/layout/AdminModuleTabs";
import { AdminPageShell } from "@/components/layout/AdminPageShell";
import { AdminFilterToolbar } from "@/components/layout/AdminFilterToolbar";
import { StatusChip } from "@/components/ui/StatusChip";
import { UserActionDialog } from "@/components/system/users/UserActionDialog";
import { UserActionMenu } from "@/components/system/users/UserActionMenu";
import { UserQuickDetailsPanel } from "@/components/system/users/UserQuickDetailsPanel";
import {
    DEFAULT_USER_ACTION_STATE,
    getUserStatusPresentation,
    normalizeUserManagementStatusFilter,
    type ManagedUser,
    type UserActionState,
    type UserActionType,
} from "@/components/system/users/userManagement";
import { ADMIN_UI_ROUTES, readPositiveIntParam, readStringParam } from "@/lib/adminUiRoutes";
import { useClientUsers } from "@/hooks/useClientUsers";

const USER_STATUS_OPTIONS = [
    { value: "all", label: "All Status" },
    { value: "live", label: "Active" },
    { value: "suspended", label: "Suspended" },
    { value: "banned", label: "Banned" },
];

const USER_ROLE_COLORS: Record<string, string> = {
    super_admin: "bg-purple-100 text-purple-700",
    admin: "bg-blue-100 text-blue-700",
    business: "bg-amber-100 text-amber-700",
};

export default function UsersPage() {
    const pathname = usePathname();
    const router = useRouter();
    const searchParams = useSearchParams();

    const {
        users,
        loading,
        isMutating,
        error,
        pagination,
        overview,
        fetchUsers,
        handleUserAction
    } = useClientUsers();

    const [searchInput, setSearchInput] = useState("");
    const [selectedUser, setSelectedUser] = useState<ManagedUser | null>(null);
    const [actionModal, setActionModal] = useState<UserActionState>(DEFAULT_USER_ACTION_STATE);
    const [dropdownOpen, setDropdownOpen] = useState<string | null>(null);

    const dropdownRef = useRef<HTMLDivElement>(null);

    const statusFilter = normalizeUserManagementStatusFilter(searchParams.get("status"));
    const verifiedFilter =
        searchParams.get("isVerified") === "true" || searchParams.get("isVerified") === "false"
            ? (searchParams.get("isVerified") as "true" | "false")
            : "all";
    const committedSearch = readStringParam(searchParams.get("q") ?? searchParams.get("search"));
    const page = readPositiveIntParam(searchParams.get("page"), 1);

    useEffect(() => {
        const timer = setTimeout(() => {
            void fetchUsers({
                page,
                q: committedSearch,
                status: statusFilter,
                isVerified: verifiedFilter
            });
        }, 300);
        return () => clearTimeout(timer);
    }, [fetchUsers, committedSearch, page, statusFilter, verifiedFilter]);

    useEffect(() => {
        setSearchInput((prev) => (prev === committedSearch ? prev : (committedSearch || "")));
    }, [committedSearch]);

    useEffect(() => {
        const nextUrl = ADMIN_UI_ROUTES.users({
            status: statusFilter !== "all" ? statusFilter : undefined,
            isVerified: verifiedFilter !== "all" ? verifiedFilter : undefined,
            q: committedSearch || undefined,
            page: page > 1 ? page : undefined,
        });
        const currentUrl = searchParams.toString() ? `${pathname}?${searchParams.toString()}` : pathname;
        if (nextUrl !== currentUrl) {
            void router.replace(nextUrl, { scroll: false });
        }
    }, [committedSearch, page, pathname, router, searchParams, statusFilter, verifiedFilter]);

    useEffect(() => {
        const normalizedSearchInput = readStringParam(searchInput);
        if (normalizedSearchInput === committedSearch) {
            return;
        }

        const timer = setTimeout(() => {
            const nextUrl = ADMIN_UI_ROUTES.users({
                status: statusFilter !== "all" ? statusFilter : undefined,
                isVerified: verifiedFilter !== "all" ? verifiedFilter : undefined,
                q: normalizedSearchInput || undefined,
            });
            const currentUrl = searchParams.toString() ? `${pathname}?${searchParams.toString()}` : pathname;
            if (nextUrl !== currentUrl) {
                void router.replace(nextUrl, { scroll: false });
            }
        }, 300);

        return () => clearTimeout(timer);
    }, [committedSearch, pathname, router, searchInput, searchParams, statusFilter, verifiedFilter]);

    // Close dropdown on outside click
    useEffect(() => {
        const handleClickOutside = (event: MouseEvent) => {
            if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
                setDropdownOpen(null);
            }
        };
        document.addEventListener("mousedown", handleClickOutside);
        return () => document.removeEventListener("mousedown", handleClickOutside);
    }, []);

    const openActionModal = (type: UserActionType, user: ManagedUser) => {
        setActionModal({ isOpen: true, type, user });
    };

    const closeActionModal = () => {
        setActionModal(DEFAULT_USER_ACTION_STATE);
    };

    const executeAction = async (reason: string) => {
        const { type, user } = actionModal;
        if (!user) return;

        const result = await handleUserAction(type, user, reason);
        if (result.success) {
            closeActionModal();
            setSelectedUser(null);
            void fetchUsers({ page, q: committedSearch, status: statusFilter, isVerified: verifiedFilter });
        }
    };

    const columns: ColumnDef<ManagedUser>[] = [
        {
            header: "User Name",
            cell: (user) => (
                <div className="flex items-center gap-3">
                    <div className="w-10 h-10 rounded-full bg-slate-100 flex items-center justify-center text-slate-400">
                        <UserIcon size={20} />
                    </div>
                    <div>
                        <div className="font-bold text-slate-900">{user.name || "Unknown"}</div>
                        <div className="text-xs text-slate-500">ID: {user.id}</div>
                    </div>
                </div>
            )
        },
        {
            header: "Mobile",
            cell: (user) => (
                <div className="text-sm font-medium text-slate-700 flex items-center gap-1">
                    {user.mobile}
                </div>
            )
        },
        {
            header: "Email",
            cell: (user) => (
                <div className="text-xs text-slate-600 flex items-center gap-1">
                    <Mail size={12} className="text-slate-400" />
                    {user.email || "No email"}
                </div>
            )
        },
        {
            header: "Role",
            cell: (user) => (
                <span
                    className={`rounded px-2 py-1 text-[10px] font-bold uppercase tracking-wider ${
                        USER_ROLE_COLORS[user.role] ?? "bg-slate-100 text-slate-600"
                    }`}
                >
                    {user.role}
                </span>
            )
        },
        {
            header: "Status",
            cell: (user) => {
                const { status, label } = getUserStatusPresentation(user.status);
                return <StatusChip status={status} label={label} />;
            }
        },
        {
            header: "Joined Date",
            cell: (user) => new Date(user.createdAt as string).toLocaleDateString()
        },
        {
            header: "Total Ads Posted",
            cell: (user) => (
                <span className="text-xs font-semibold text-slate-700">
                    {Number(user.totalAdsPosted ?? user.totalAds ?? 0)}
                </span>
            )
        },
        {
            header: "",
            cell: (user) => (
                <UserActionMenu
                    user={user}
                    isOpen={dropdownOpen === user.id}
                    menuRef={dropdownRef}
                    onToggle={() => setDropdownOpen(dropdownOpen === user.id ? null : user.id)}
                    onClose={() => setDropdownOpen(null)}
                    onOpenDetails={setSelectedUser}
                    onOpenAction={openActionModal}
                />
            ),
        }
    ];

    return (
        <AdminPageShell
            title="User Management"
            description="Review, verify and manage platform accounts"
            tabs={
                <AdminModuleTabs
                    tabs={[
                        { label: "All Users", href: ADMIN_UI_ROUTES.users() },
                        { label: "Active", href: ADMIN_UI_ROUTES.users({ status: "live" }), count: overview.activeUsers },
                        { label: "Suspended", href: ADMIN_UI_ROUTES.users({ status: "suspended" }), count: overview.suspendedUsers },
                        { label: "Banned", href: ADMIN_UI_ROUTES.users({ status: "banned" }), count: overview.bannedUsers },
                        { label: "Verified", href: ADMIN_UI_ROUTES.users({ isVerified: "true" }), count: overview.verifiedUsers },
                    ]}
                />
            }
            className="h-full overflow-hidden"
        >
        <div className="relative flex h-full min-h-0 overflow-hidden">
            <div className={`flex min-h-0 flex-1 flex-col overflow-hidden transition-all duration-300 ${selectedUser ? 'pr-[400px]' : ''}`}>
                <div className="flex min-h-0 flex-1 flex-col gap-6">

                    <div className="grid grid-cols-1 gap-3 md:grid-cols-2 xl:grid-cols-5">
                        <Link href={ADMIN_UI_ROUTES.users()} className="rounded-xl border border-slate-200 bg-white p-4 shadow-sm transition hover:-translate-y-0.5 hover:shadow-md">
                            <p className="text-xs font-semibold uppercase tracking-wide text-slate-500">Total Users</p>
                            <p className="mt-2 text-2xl font-bold text-slate-900">{overview.totalUsers.toLocaleString()}</p>
                        </Link>
                        <Link href={ADMIN_UI_ROUTES.users({ status: "live" })} className="rounded-xl border border-emerald-200 bg-emerald-50/40 p-4 shadow-sm transition hover:-translate-y-0.5 hover:shadow-md">
                            <p className="text-xs font-semibold uppercase tracking-wide text-emerald-700">Active Users</p>
                            <p className="mt-2 text-2xl font-bold text-emerald-700">{overview.activeUsers.toLocaleString()}</p>
                        </Link>
                        <Link href={ADMIN_UI_ROUTES.users({ status: "suspended" })} className="rounded-xl border border-amber-200 bg-amber-50/40 p-4 shadow-sm transition hover:-translate-y-0.5 hover:shadow-md">
                            <p className="text-xs font-semibold uppercase tracking-wide text-amber-700">Suspended Users</p>
                            <p className="mt-2 text-2xl font-bold text-amber-700">{overview.suspendedUsers.toLocaleString()}</p>
                        </Link>
                        <Link href={ADMIN_UI_ROUTES.users({ status: "banned" })} className="rounded-xl border border-red-200 bg-red-50/40 p-4 shadow-sm transition hover:-translate-y-0.5 hover:shadow-md">
                            <p className="text-xs font-semibold uppercase tracking-wide text-red-700">Banned Users</p>
                            <p className="mt-2 text-2xl font-bold text-red-700">{overview.bannedUsers.toLocaleString()}</p>
                        </Link>
                        <Link href={ADMIN_UI_ROUTES.users({ isVerified: "true" })} className="rounded-xl border border-blue-200 bg-blue-50/40 p-4 shadow-sm transition hover:-translate-y-0.5 hover:shadow-md">
                            <p className="text-xs font-semibold uppercase tracking-wide text-blue-700">Verified Users</p>
                            <p className="mt-2 text-2xl font-bold text-blue-700">{overview.verifiedUsers.toLocaleString()}</p>
                        </Link>
                    </div>

                    <AdminFilterToolbar
                        search={searchInput}
                        onSearchChange={setSearchInput}
                        searchPlaceholder="Search by name, email or mobile..."
                        status={statusFilter}
                        onStatusChange={(value) => {
                            const nextStatus = normalizeUserManagementStatusFilter(value);
                            void router.replace(
                                ADMIN_UI_ROUTES.users({
                                    status: nextStatus !== "all" ? nextStatus : undefined,
                                    isVerified: verifiedFilter !== "all" ? verifiedFilter : undefined,
                                    q: committedSearch || undefined,
                                }),
                                { scroll: false }
                            );
                        }}
                        statusOptions={USER_STATUS_OPTIONS}
                        extraFilters={
                            <select
                                className="rounded-lg border border-slate-200 bg-slate-50 px-2.5 py-1.5 text-sm font-medium focus:outline-none focus:ring-2 focus:ring-sky-200"
                                value={verifiedFilter}
                                onChange={(event) => {
                                    const nextVerified = event.target.value as "all" | "true" | "false";
                                    void router.replace(
                                        ADMIN_UI_ROUTES.users({
                                            status: statusFilter !== "all" ? statusFilter : undefined,
                                            isVerified: nextVerified !== "all" ? nextVerified : undefined,
                                            q: committedSearch || undefined,
                                        }),
                                        { scroll: false }
                                    );
                                }}
                            >
                                <option value="all">All Verification</option>
                                <option value="true">Verified</option>
                                <option value="false">Unverified</option>
                            </select>
                        }
                    />

                    {error ? (
                        <div className="flex items-center gap-2 rounded-lg border border-red-100 bg-red-50 px-4 py-3 text-sm text-red-600">
                            <AlertCircle size={16} />
                            <span>{error}</span>
                        </div>
                    ) : null}

                    <div className="min-h-0 flex-1">
                        <DataTable
                            data={users}
                            columns={columns}
                            isLoading={loading}
                            emptyMessage="No users matching your criteria"
                            pagination={{
                                currentPage: page,
                                totalPages: pagination.pages || 1,
                                totalItems: pagination.total,
                                pageSize: pagination.limit,
                                onPageChange: (nextPage) => {
                                    void router.replace(
                                        ADMIN_UI_ROUTES.users({
                                            status: statusFilter !== "all" ? statusFilter : undefined,
                                            isVerified: verifiedFilter !== "all" ? verifiedFilter : undefined,
                                            q: committedSearch || undefined,
                                            page: nextPage > 1 ? nextPage : undefined,
                                        }),
                                        { scroll: false }
                                    );
                                }
                            }}
                        />
                    </div>
                </div>
            </div>

            {selectedUser ? (
                <UserQuickDetailsPanel user={selectedUser} onClose={() => setSelectedUser(null)} />
            ) : null}

            <UserActionDialog
                open={actionModal.isOpen}
                user={actionModal.user}
                actionType={actionModal.type}
                isSubmitting={isMutating}
                onClose={closeActionModal}
                onConfirm={executeAction}
            />
        </div>
        </AdminPageShell>
    );
}

"use client";

import { useEffect, useMemo, useState, useRef } from "react";
import { AlertCircle, RefreshCcw, EyeOff, ChevronDown, Loader2 } from "lucide-react";
import { AdsTable } from "@/components/moderation/AdsTable";
import { RejectAdModal } from "@/components/moderation/RejectAdModal";
import { ViewAdModal } from "@/components/moderation/ViewAdModal";
import { AdminModuleTabs } from "@/components/layout/AdminModuleTabs";
import { AdminPageShell } from "@/components/layout/AdminPageShell";
import { AdminFilterToolbar } from "@/components/layout/AdminFilterToolbar";
import { moderationTabs } from "@/components/layout/adminModuleTabSets";
import { AdminErrorBoundary } from "@/components/common/AdminErrorBoundary";
import { getListingPresentation } from "@/components/moderation/listingPresentation";
import { CatalogModal } from "@/components/catalog/CatalogModal";

import { useAdFilters } from "./hooks/useAdFilters";
import { useAdSelection } from "./hooks/useAdSelection";
import { useAdTableData } from "./hooks/useAdTableData";
import { useAdActions } from "./hooks/useAdActions";
import { ModerationFilters } from "@/components/moderation/moderationTypes";

const SORT_OPTIONS: Array<{ label: string; value: ModerationFilters["sort"] }> = [
    { label: "Newest", value: "newest" },
    { label: "Oldest", value: "oldest" },
    { label: "Price High", value: "price_high" },
    { label: "Price Low", value: "price_low" }
];

type AdsViewProps = {
    mode?: "ads";
    listingType?: "ad" | "service" | "spare_part";
};

export default function AdsView({ mode: _mode = "ads", listingType }: AdsViewProps) {
    const presentation = getListingPresentation(listingType);
    const entityLabel = presentation.actionEntityLabel;
    const entityLabelPlural = presentation.actionEntityLabelPlural;

    const [refreshKey, setRefreshKey] = useState(0);
    const refresh = () => setRefreshKey((value) => value + 1);

    // ── Local UI State ─────────────────────────────────────────────────────────
    const [columnVisibility, setColumnVisibility] = useState<Record<string, boolean>>({
        select: true,
        image: true,
        details: true,
        seller: true,
        location: true,
        attribute: true,
        risk: true,
        status: true,
        created: true,
        actions: true
    });
    const [showColumnMenu, setShowColumnMenu] = useState(false);
    const columnMenuRef = useRef<HTMLDivElement>(null);

    // ── Modular Hooks ──────────────────────────────────────────────────────────
    const { 
        filters, page, pageSize, updateFilter, clearFilters, replaceRoute 
    } = useAdFilters(listingType);

    const { 
        items, pagination, summary: _summary, isLoading, error, moduleTabs, activeStatusOptions 
    } = useAdTableData({ filters, page, pageSize, refreshKey });

    const { 
        selectedIds, selectedCount, toggleSelect, toggleSelectAll, setSelectedIds 
    } = useAdSelection(items);

    const {
        viewAd, viewModalOpen, setViewModalOpen, viewLoading, viewError, handleView, setViewAd, setViewError,
        rejectModalOpen, setRejectModalOpen, rejectTitle, rejectTargetIds, isMutating, setRejectTargetIds, setRejectTitle,
        openSingleReject, openBulkReject, handleRejectSubmit,
        handleApprove, handleDeactivate, handleActivate, handleDelete, handleBanSeller, handleBulkApprove, handleBulkDelete,
        handleModalApprove, handleModalDeactivate, handleModalActivate, handleModalBlockSeller, handleModalExtend,
        // Added confirmations
        deleteModalOpen, setDeleteModalOpen, deleteTargetIds, deleteDisplayTitle, handleConfirmDelete,
        banModalOpen, setBanModalOpen, banTargetSellerName, handleConfirmBan,
    } = useAdActions({
        items,
        entityLabel,
        entityLabelPlural,
        refresh,
        selectedIds,
        setSelectedIds
    });

    // ── Sync: Page existence check ───────────────────────────────────────────
    useEffect(() => {
        if (page > pagination.pages && pagination.pages > 0) {
            replaceRoute({ page: pagination.pages });
        }
    }, [page, pagination.pages, replaceRoute]);

    // ── UI: Click outside column menu ────────────────────────────────────────
    useEffect(() => {
        const handleClickOutside = (event: MouseEvent) => {
            if (columnMenuRef.current && !columnMenuRef.current.contains(event.target as Node)) {
                setShowColumnMenu(false);
            }
        };
        document.addEventListener("mousedown", handleClickOutside);
        return () => document.removeEventListener("mousedown", handleClickOutside);
    }, []);

    const columnOptions = useMemo(() => [
        { id: "select", label: "Checkboxes" },
        { id: "image", label: "Image" },
        { id: "details", label: "Details" },
        { id: "seller", label: "Seller" },
        { id: "location", label: "Location" },
        { id: "attribute", label: presentation.attributeHeader },
        { id: "risk", label: "Risk" },
        { id: "status", label: "Status" },
        { id: "created", label: "Created" },
        { id: "actions", label: "Actions" },
    ], [presentation.attributeHeader]);

    return (
        <AdminPageShell
            headerVariant="compact"
            title={listingType ? presentation.pageTitle : "Listings"}
            tabs={
                <div className="flex flex-col gap-4 mb-2">
                    <AdminModuleTabs tabs={moderationTabs} variant="primary" />
                    <AdminModuleTabs tabs={moduleTabs} variant="pills" />
                </div>
            }
            actions={
                <div className="flex items-center gap-2">
                    <div className="relative" ref={columnMenuRef}>
                        <button
                            type="button"
                            onClick={() => setShowColumnMenu(!showColumnMenu)}
                            className="inline-flex items-center gap-2 rounded-lg border border-slate-200 bg-white px-3 py-2 text-sm font-medium text-slate-700 hover:bg-slate-50 transition-all active:scale-95"
                        >
                            <EyeOff size={14} /> 
                            <span>Columns</span>
                            <ChevronDown size={12} className={`transition-transform duration-200 ${showColumnMenu ? "rotate-180" : ""}`} />
                        </button>

                        {showColumnMenu && (
                            <div className="absolute right-0 top-full z-40 mt-2 min-w-[200px] rounded-xl border border-slate-200 bg-white p-2 shadow-xl animate-in fade-in zoom-in duration-200">
                                <div className="px-2 py-1.5 text-[10px] font-bold uppercase tracking-wider text-slate-400">
                                    Toggle Columns
                                </div>
                                <div className="max-h-[300px] overflow-y-auto custom-scrollbar">
                                    {columnOptions.map((opt) => (
                                        <label
                                            key={opt.id}
                                            className="flex items-center gap-2.5 rounded-lg px-2 py-2 text-sm text-slate-700 hover:bg-slate-50 cursor-pointer transition-colors"
                                        >
                                            <input
                                                type="checkbox"
                                                className="w-4 h-4 rounded border-slate-300 text-sky-600 focus:ring-sky-200 cursor-pointer"
                                                checked={columnVisibility[opt.id] !== false}
                                                onChange={(e) => {
                                                    setColumnVisibility(prev => ({
                                                        ...prev,
                                                        [opt.id]: e.target.checked
                                                    }));
                                                }}
                                            />
                                            <span className="font-medium">{opt.label}</span>
                                        </label>
                                    ))}
                                </div>
                            </div>
                        )}
                    </div>

                    <button
                        type="button"
                        onClick={refresh}
                        className="inline-flex items-center gap-2 rounded-lg border border-slate-200 bg-white px-3 py-2 text-sm font-medium text-slate-700 hover:bg-slate-50 transition-all active:scale-95"
                    >
                        <RefreshCcw size={14} /> 
                        <span>Refresh</span>
                    </button>
                </div>
            }
        >
            <div className="flex min-h-0 flex-1 flex-col gap-3">
                {/* Filter toolbar */}
                <AdminFilterToolbar
                    search={filters.search}
                    onSearchChange={(val) => updateFilter("search", val)}
                    searchPlaceholder="Search title, description, seller, phone"
                    status={filters.status}
                    onStatusChange={(val) => updateFilter("status", val as ModerationFilters["status"])}
                    statusOptions={activeStatusOptions}
                    extraFilters={
                        <>
                            <input
                                value={filters.sellerId}
                                onChange={(e) => updateFilter("sellerId", e.target.value)}
                                placeholder="Seller ID"
                                className="rounded-lg border border-slate-200 bg-slate-50 px-2.5 py-1.5 text-sm focus:outline-none focus:ring-2 focus:ring-sky-200 w-32"
                            />
                            <input
                                value={filters.locationId}
                                onChange={(e) => updateFilter("locationId", e.target.value)}
                                placeholder="Location ID"
                                className="rounded-lg border border-slate-200 bg-slate-50 px-2.5 py-1.5 text-sm focus:outline-none focus:ring-2 focus:ring-sky-200 w-44"
                            />
                            <select
                                value={filters.sort}
                                onChange={(e) => updateFilter("sort", e.target.value as ModerationFilters["sort"])}
                                className="rounded-lg border border-slate-200 bg-slate-50 px-2.5 py-1.5 text-sm font-medium focus:outline-none focus:ring-2 focus:ring-sky-200"
                            >
                                {SORT_OPTIONS.map((opt) => (
                                    <option key={opt.value} value={opt.value}>{opt.label}</option>
                                ))}
                            </select>
                            <input
                                type="date"
                                value={filters.dateFrom}
                                onChange={(e) => updateFilter("dateFrom", e.target.value)}
                                className="rounded-lg border border-slate-200 bg-slate-50 px-2.5 py-1.5 text-sm focus:outline-none focus:ring-2 focus:ring-sky-200"
                            />
                            <input
                                type="date"
                                value={filters.dateTo}
                                onChange={(e) => updateFilter("dateTo", e.target.value)}
                                className="rounded-lg border border-slate-200 bg-slate-50 px-2.5 py-1.5 text-sm focus:outline-none focus:ring-2 focus:ring-sky-200"
                            />
                            <button
                                type="button"
                                onClick={clearFilters}
                                className="rounded-lg border border-slate-200 bg-white px-2.5 py-1.5 text-xs font-medium text-slate-600 hover:bg-slate-50"
                            >
                                Clear
                            </button>
                        </>
                    }
                />

                {error && (
                    <div className="flex items-center gap-2 rounded-lg border border-red-100 bg-red-50 p-4 text-sm font-medium text-red-600">
                        <AlertCircle size={16} /> {error}
                    </div>
                )}

                <div className="min-h-0 flex-1">
                    <AdsTable
                        data={items}
                        listingType={listingType}
                        isLoading={isLoading}
                        emptyMessage={`No ${entityLabelPlural} matched current moderation filters`}
                        currentPage={page}
                        totalPages={pagination.pages}
                        totalItems={pagination.total}
                        pageSize={pagination.limit}
                        selectedIds={selectedIds}
                        onToggleSelect={toggleSelect}
                        onToggleSelectAll={toggleSelectAll}
                        onPageChange={(nextPage) => replaceRoute({ page: nextPage })}
                        onPageSizeChange={(size) => {
                            replaceRoute({ page: 1, limit: size });
                        }}
                        onView={handleView}
                        onApprove={(item) => void handleApprove(item)}
                        onReject={openSingleReject}
                        onDeactivate={(item) => void handleDeactivate(item)}
                        onActivate={(item) => void handleActivate(item)}
                        onDelete={(item) => void handleDelete(item)}
                        onBanSeller={(item) => void handleBanSeller(item)}
                        showCheckboxes={filters.status === 'pending'}
                        columnVisibility={columnVisibility}
                        onColumnVisibilityChange={setColumnVisibility}
                        hideColumnVisibilityButton={true}
                        bulkActions={
                            filters.status === 'pending' ? (
                                <>
                                    <button
                                        type="button"
                                        onClick={() => void handleBulkApprove()}
                                        disabled={selectedCount === 0}
                                        className="rounded-lg bg-emerald-600 px-3 py-2 text-xs font-semibold text-white hover:bg-emerald-700 disabled:cursor-not-allowed disabled:opacity-50"
                                    >
                                        Approve Selected
                                    </button>
                                    <button
                                        type="button"
                                        onClick={openBulkReject}
                                        disabled={selectedCount === 0}
                                        className="rounded-lg bg-red-600 px-3 py-2 text-xs font-semibold text-white hover:bg-red-700 disabled:cursor-not-allowed disabled:opacity-50"
                                    >
                                        Reject Selected
                                    </button>
                                    <button
                                        type="button"
                                        onClick={() => void handleBulkDelete()}
                                        disabled={selectedCount === 0}
                                        className="rounded-lg border border-slate-300 bg-white px-3 py-2 text-xs font-semibold text-slate-700 hover:bg-slate-50 disabled:cursor-not-allowed disabled:opacity-50"
                                    >
                                        Delete Selected
                                    </button>
                                </>
                            ) : undefined
                        }
                    />
                </div>

                <AdminErrorBoundary fallbackLabel="Moderation Modal Error">
                    <RejectAdModal
                        open={rejectModalOpen}
                        title={rejectTitle}
                        entityLabel={entityLabel}
                        affectedCount={rejectTargetIds.length}
                        isSubmitting={isMutating}
                        onClose={() => {
                            setRejectModalOpen(false);
                            setRejectTargetIds([]);
                            setRejectTitle(undefined);
                        }}
                        onSubmit={handleRejectSubmit}
                    />

                    {/* Hardened Deletion Modal */}
                    <CatalogModal
                        isOpen={deleteModalOpen}
                        onClose={() => !isMutating && setDeleteModalOpen(false)}
                        title={`Delete ${entityLabelPlural}`}
                    >
                        <div className="p-6 space-y-4">
                            <div className="flex items-start gap-4 p-4 bg-red-50 rounded-xl border border-red-200">
                                <AlertCircle className="h-5 w-5 text-red-600 shrink-0 mt-0.5" />
                                <div>
                                    <h3 className="text-sm font-bold text-red-900">Permanent Action</h3>
                                    <p className="mt-1 text-sm text-red-800 leading-relaxed">
                                        Are you sure you want to delete {deleteTargetIds.length === 1 ? `"${deleteDisplayTitle || "this " + entityLabel}"` : `${deleteTargetIds.length} selected ${entityLabelPlural}`}? 
                                        This action cannot be undone and will remove all associated data.
                                    </p>
                                </div>
                            </div>
                            <div className="flex justify-end gap-3 pt-2">
                                <button
                                    type="button"
                                    disabled={isMutating}
                                    onClick={() => setDeleteModalOpen(false)}
                                    className="px-4 py-2 rounded-lg border border-slate-200 text-sm font-semibold text-slate-600 hover:bg-slate-50 transition-all"
                                >
                                    Cancel
                                </button>
                                <button
                                    type="button"
                                    disabled={isMutating}
                                    onClick={handleConfirmDelete}
                                    className="flex items-center gap-2 px-4 py-2 rounded-lg bg-red-600 text-white text-sm font-bold hover:bg-red-700 transition-all shadow-lg shadow-red-200"
                                >
                                    {isMutating ? <><Loader2 size={16} className="animate-spin" /> Deleting...</> : "Confirm Delete"}
                                </button>
                            </div>
                        </div>
                    </CatalogModal>

                    {/* Hardened Ban Modal */}
                    <CatalogModal
                        isOpen={banModalOpen}
                        onClose={() => !isMutating && setBanModalOpen(false)}
                        title="Block Seller"
                    >
                        <div className="p-6 space-y-4">
                            <div className="flex items-start gap-4 p-4 bg-amber-50 rounded-xl border border-amber-200">
                                <AlertCircle className="h-5 w-5 text-amber-600 shrink-0 mt-0.5" />
                                <div>
                                    <h3 className="text-sm font-bold text-amber-900">Restrict Platform Access</h3>
                                    <p className="mt-1 text-sm text-amber-800 leading-relaxed">
                                        You are about to block <strong>{banTargetSellerName || "this seller"}</strong>. 
                                        They will be unable to post new {entityLabelPlural} or manage existing ones until globally reinstated by an admin.
                                    </p>
                                </div>
                            </div>
                            <div className="flex justify-end gap-3 pt-2">
                                <button
                                    type="button"
                                    disabled={isMutating}
                                    onClick={() => setBanModalOpen(false)}
                                    className="px-4 py-2 rounded-lg border border-slate-200 text-sm font-semibold text-slate-600 hover:bg-slate-50 transition-all"
                                >
                                    Cancel
                                </button>
                                <button
                                    type="button"
                                    disabled={isMutating}
                                    onClick={handleConfirmBan}
                                    className="flex items-center gap-2 px-4 py-2 rounded-lg bg-amber-600 text-white text-sm font-bold hover:bg-amber-700 transition-all shadow-lg shadow-amber-200"
                                >
                                    {isMutating ? <><Loader2 size={16} className="animate-spin" /> Blocking...</> : "Block Seller"}
                                </button>
                            </div>
                        </div>
                    </CatalogModal>

                    <ViewAdModal
                        open={viewModalOpen}
                        ad={viewAd}
                        listingType={listingType}
                        loading={viewLoading}
                        error={viewError}
                        onClose={() => {
                            setViewModalOpen(false);
                            setViewAd(null);
                            setViewError("");
                        }}
                        onApprove={handleModalApprove}
                        onReject={(adId) => {
                            const ad = items.find((item) => item.id === adId) || viewAd;
                            if (ad) openSingleReject(ad);
                        }}
                        onDeactivate={handleModalDeactivate}
                        onActivate={handleModalActivate}
                        onBlockSeller={handleModalBlockSeller}
                        onExtend={handleModalExtend}
                    />
                </AdminErrorBoundary>
            </div>
        </AdminPageShell>
    );
}

