"use client";

import { useState, useEffect } from "react";
import type { ModerationItem } from "@/components/moderation/moderationTypes";

export function useAdSelection(items: ModerationItem[]) {
    const [selectedIds, setSelectedIds] = useState<string[]>([]);

    const selectedCount = selectedIds.length;

    // Cleanup: Remove selected IDs that are no longer in the current item list
    // This typically happens on pagination or status changes
    useEffect(() => {
        setSelectedIds((prev) => prev.filter((id) => items.some((item) => item.id === id)));
    }, [items]);

    const toggleSelect = (adId: string, checked: boolean) => {
        setSelectedIds((prev) => {
            if (checked) return Array.from(new Set([...prev, adId]));
            return prev.filter((id) => id !== adId);
        });
    };

    const toggleSelectAll = (checked: boolean) => {
        const currentIds = items.map((item) => item.id);
        setSelectedIds((prev) => {
            if (checked) return Array.from(new Set([...prev, ...currentIds]));
            return prev.filter((id) => !currentIds.includes(id));
        });
    };

    return {
        selectedIds,
        selectedCount,
        toggleSelect,
        toggleSelectAll,
        setSelectedIds
    };
}

"use client";
import { useCallback, useEffect, useState } from "react";
import { usePathname, useRouter, useSearchParams } from "next/navigation";
import {
    Building2,
    MapPin,
    Ban,
    RotateCcw,
    ChartBar,
} from "lucide-react";
import { format } from "date-fns";
import { ColumnDef } from "@/components/ui/DataTable";
import { AdminPageShell } from "@/components/layout/AdminPageShell";
import { BusinessSuspendModal } from "@/components/business/BusinessSuspendModal";
import { AdminModuleTabs } from "@/components/layout/AdminModuleTabs";
import { useAdminBusinessList } from "@/hooks/useAdminBusinessList";
import type { Business } from "@esparex/shared/types";
import {
    buildUrlWithSearchParams,
    normalizeSearchParamValue,
    parsePositiveIntParam,
    updateSearchParams,
} from "@/lib/urlSearchParams";
import {
    BusinessActionButton,
    buildBusinessModalController,
    createBusinessActionsColumn,
    createBusinessStatusColumn,
    BusinessListModals,
    BusinessListTable,
    BusinessSearchToolbar,
    BusinessTypesCell,
} from "@/components/business/BusinessListPrimitives";

const DEFAULT_STATUS = "live";
const BUSINESS_MASTER_STATUSES = new Set(["live", "suspended", "pending", "deleted", "all"]);

const mapOverview = (data: Record<string, unknown>) => ({
    total: Number(data.total || 0),
    pending: Number(data.pending || 0),
    live: Number(data.live || data.approved || 0),
    suspended: Number(data.suspended || 0),
    deleted: Number(data.deleted || 0),
});

export default function BusinessesView() {
    const router = useRouter();
    const pathname = usePathname();
    const searchParams = useSearchParams();

    const [suspendTarget, setSuspendTarget] = useState<Business | null>(null);
    const rawStatus = searchParams.get("status");
    const rawSearch = searchParams.get("q") ?? searchParams.get("search");
    const rawLocationId = searchParams.get("locationId");
    const rawPage = searchParams.get("page");

    const activeTab =
        rawStatus === "approved" || rawStatus === "active"
            ? DEFAULT_STATUS
            : rawStatus && BUSINESS_MASTER_STATUSES.has(rawStatus)
                ? rawStatus
                : DEFAULT_STATUS;
    const search = normalizeSearchParamValue(rawSearch);
    const locationIdFilter = normalizeSearchParamValue(rawLocationId);
    const page = parsePositiveIntParam(rawPage, 1);

    const replaceQueryState = useCallback((updates: Record<string, string | number | null | undefined>) => {
        const nextUrl = buildUrlWithSearchParams(pathname, updateSearchParams(searchParams, updates));
        const currentUrl = buildUrlWithSearchParams(pathname, new URLSearchParams(searchParams.toString()));
        if (nextUrl !== currentUrl) {
            router.replace(nextUrl, { scroll: false });
        }
    }, [pathname, router, searchParams]);

    const businessList = useAdminBusinessList({
        activeTab,
        search,
        page,
        initialOverview: { total: 0, pending: 0, live: 0, suspended: 0, deleted: 0 },
        mapOverview,
        extraQueryParams: {
            locationId: locationIdFilter,
            includeDeleted: activeTab === "deleted" || activeTab === "all" ? "true" : undefined,
        },
    });
    const { businesses, loading, error, pagination, overview, handleSuspend, handleActivate } = businessList;

    useEffect(() => {
        const nextUrl = buildUrlWithSearchParams(
            pathname,
            updateSearchParams(searchParams, {
                status: activeTab,
                q: search,
                locationId: locationIdFilter,
                page: page > 1 ? page : null,
            })
        );
        const currentUrl = buildUrlWithSearchParams(pathname, new URLSearchParams(searchParams.toString()));

        if (nextUrl !== currentUrl) {
            router.replace(nextUrl, { scroll: false });
        }
    }, [activeTab, locationIdFilter, page, pathname, rawStatus, router, search, searchParams]);

    useEffect(() => {
        if (!loading && page > pagination.pages) {
            replaceQueryState({ page: pagination.pages > 1 ? pagination.pages : null });
        }
    }, [loading, page, pagination.pages, replaceQueryState]);

    const columns: ColumnDef<Business>[] = [
        {
            header: "Business",
            cell: (biz) => (
                <div className="flex items-center gap-3 min-w-0">
                    <div className="w-10 h-10 shrink-0 rounded-xl bg-slate-100 flex items-center justify-center text-slate-400">
                        <Building2 size={20} />
                    </div>
                    <div className="min-w-0">
                        <div className="font-bold text-slate-900 leading-tight truncate">{biz.name}</div>
                        <div className="text-[10px] text-slate-400 font-mono mt-0.5 truncate">{biz.id}</div>
                    </div>
                </div>
            ),
        },
        {
            header: "Trust",
            cell: (biz) => {
                const score = biz.trustScore ?? 0;
                // Premium HSL-based dynamic colors
                const hue = Math.round((score / 100) * 120); // 0 (red) to 120 (green)
                const color = `hsl(${hue}, 84%, 45%)`;
                const bg = `hsl(${hue}, 84%, 96%)`;

                return (
                    <div className="flex flex-col gap-1.5 w-16 group cursor-default">
                        <div className="flex items-center justify-between">
                             <div className="text-[10px] font-black tracking-tighter tabular-nums" style={{ color }}>
                               {score}%
                             </div>
                             {score > 85 && (
                               <div className="w-1.5 h-1.5 rounded-full bg-emerald-400 animate-pulse shadow-[0_0_4px_theme(colors.emerald.400)]" />
                             )}
                        </div>
                        <div className="h-1.5 bg-slate-100 rounded-full overflow-hidden border border-slate-200/50 shadow-inner">
                            <div 
                                className="h-full transition-all duration-700 ease-out shadow-[0_0_8px_rgba(0,0,0,0.1)]" 
                                style={{ 
                                    width: `${score}%`, 
                                    backgroundColor: color,
                                    backgroundImage: `linear-gradient(to right, transparent, rgba(255,255,255,0.3))` 
                                }} 
                            />
                        </div>
                    </div>
                );
            },
        },
        {
            header: "Category",
            cell: (biz) => <BusinessTypesCell businessTypes={biz.businessTypes} />,
        },
        {
            header: "Location",
            cell: (biz) => (
                <div className="flex items-center gap-1.5 text-xs text-slate-600">
                    <MapPin size={12} className="text-slate-400 shrink-0" />
                    <span className="truncate max-w-[110px]">{biz.location?.city || "—"}</span>
                </div>
            ),
        },
        {
            header: "Active Since",
            cell: (biz) => (
                <div className="space-y-0.5">
                    <div className="text-xs text-slate-700 font-medium">
                        {biz.approvedAt ? format(new Date(biz.approvedAt), "MMM d, yyyy") : "N/A"}
                    </div>
                    {biz.expiresAt && (
                        <div className="text-[9px] text-slate-400 italic">
                            Exp {format(new Date(biz.expiresAt), "MMM d, yyyy")}
                        </div>
                    )}
                </div>
            ),
        },
        createBusinessStatusColumn(true),
        createBusinessActionsColumn({
            onView: businessList.setSelectedBusiness,
            onEdit: businessList.setModifyTarget,
            onDelete: businessList.setDeleteTarget,
            editTitle: "Edit Business",
            deleteTitle: "Delete Business",
            canEdit: (biz) => !biz.isDeleted,
            canDelete: (biz) => !biz.isDeleted,
            renderExtraActions: (biz) =>
                biz.status === "live" ? (
                    <BusinessActionButton
                        onClick={() => setSuspendTarget(biz)}
                        title="Suspend Business"
                        tone="warning"
                        icon={<Ban size={15} />}
                    />
                ) : biz.status === "suspended" ? (
                    <BusinessActionButton
                        onClick={() => void handleActivate(biz.id)}
                        title="Reactivate Business"
                        tone="success"
                        icon={<RotateCcw size={15} />}
                    />
                ) : undefined,
        }),
    ];

    return (
        <AdminPageShell
            title="Business Master"
            description="Single admin surface for pending, live, suspended, deleted, and historical business accounts"
            headerVariant="compact"
        >
            <div className="space-y-6">
                <div className="grid grid-cols-2 sm:grid-cols-5 gap-3">
                    {[
                        { label: "All", value: overview.total, color: "text-slate-700" },
                        { label: "Live", value: overview.live, color: "text-emerald-600" },
                        { label: "Pending", value: overview.pending, color: "text-amber-600" },
                        { label: "Suspended", value: overview.suspended, color: "text-red-600" },
                        { label: "Deleted", value: overview.deleted, color: "text-slate-500" },
                    ].map(({ label, value, color }) => (
                        <div key={label} className="bg-white rounded-xl border border-slate-200 p-3 flex items-center gap-3 shadow-sm">
                            <ChartBar size={16} className="text-slate-300" />
                            <div>
                                <div className={`text-lg font-bold ${color}`}>{value}</div>
                                <div className="text-[10px] text-slate-400 font-semibold uppercase tracking-wider">{label}</div>
                            </div>
                        </div>
                    ))}
                </div>

                <AdminModuleTabs
                    tabs={[
                        {
                            label: "Live",
                            href: buildUrlWithSearchParams(
                                pathname,
                                updateSearchParams(searchParams, { status: "live", page: null })
                            ),
                            count: overview.live,
                        },
                        {
                            label: "Suspended",
                            href: buildUrlWithSearchParams(
                                pathname,
                                updateSearchParams(searchParams, { status: "suspended", page: null })
                            ),
                            count: overview.suspended,
                        },
                        {
                            label: "Pending",
                            href: buildUrlWithSearchParams(
                                pathname,
                                updateSearchParams(searchParams, { status: "pending", page: null })
                            ),
                            count: overview.pending,
                        },
                        {
                            label: "Deleted",
                            href: buildUrlWithSearchParams(
                                pathname,
                                updateSearchParams(searchParams, { status: "deleted", page: null })
                            ),
                            count: overview.deleted,
                        },
                        {
                            label: "All",
                            href: buildUrlWithSearchParams(
                                pathname,
                                updateSearchParams(searchParams, { status: "all", page: null })
                            ),
                            count: overview.total,
                        },
                    ]}
                />

                <BusinessSearchToolbar
                    search={search}
                    onSearchChange={(value) => replaceQueryState({ q: value, page: null })}
                    placeholder="Search by name, mobile, email..."
                    summary={<>{pagination.total} results</>}
                    wrap
                    searchClassName="relative flex-1 min-w-[200px] max-w-sm"
                    extraFilters={
                        <input
                            type="text"
                            placeholder="Filter by location ID..."
                            className="px-3 py-2 bg-slate-50 border border-slate-200 rounded-lg text-sm focus:outline-none focus:ring-2 focus:ring-primary/20 focus:border-primary transition-all w-52"
                            value={locationIdFilter}
                            onChange={(event) => replaceQueryState({ locationId: event.target.value, page: null })}
                        />
                    }
                />

                <BusinessListTable
                    data={businesses}
                    columns={columns}
                    isLoading={loading}
                    page={page}
                    setPage={(nextPage) => replaceQueryState({ page: nextPage > 1 ? nextPage : null })}
                    pagination={pagination}
                    onRowClick={(biz) => businessList.setSelectedBusiness(biz)}
                    emptyMessage={error || "No businesses found."}
                />
            </div>

            <BusinessListModals
                controller={buildBusinessModalController(businesses, businessList)}
                onApproveFromDetails={(business) => void handleActivate(business.id)}
                onSuspendFromDetails={(business) => setSuspendTarget(business)}
                onActivateFromDetails={(id) => void handleActivate(id)}
                deleteDescription={
                    <>
                        Soft-deletes the business and expires all listings. This cannot be undone automatically.
                    </>
                }
                extraDialogs={
                    suspendTarget && (
                        <BusinessSuspendModal
                            businessName={suspendTarget.name}
                            onClose={() => setSuspendTarget(null)}
                            onConfirm={async (reason) => {
                                await handleSuspend(suspendTarget.id, reason);
                                setSuspendTarget(null);
                            }}
                        />
                    )
                }
            />
        </AdminPageShell>
    );
}

"use client";

import { useState, useEffect, useCallback, type ReactNode } from "react";
import { usePathname, useRouter, useSearchParams } from "next/navigation";
import { RefreshCcw, Search, Shield, AlertTriangle, Ban, X } from "lucide-react";
import { AdminPageShell } from "@/components/layout/AdminPageShell";
import { useToast } from "@/context/ToastContext";
import {
  fetchAdminChats,
  adminMuteChat,
  adminExportChat,
  type AdminConvSummary,
  type AdminChatFilter,
} from "@/lib/api/adminChat";
import {
  ADMIN_UI_ROUTES,
  buildAdminRouteWithMergedQuery,
  readPositiveIntParam,
  readStringParam,
} from "@/lib/adminUiRoutes";

const FILTER_OPTIONS: { value: AdminChatFilter; label: string; icon?: ReactNode }[] = [
  { value: "all", label: "All Chats" },
  { value: "reported", label: "Reported", icon: <AlertTriangle size={14} /> },
  { value: "high_risk", label: "High Risk", icon: <Shield size={14} /> },
  { value: "blocked", label: "Blocked", icon: <Ban size={14} /> },
  { value: "closed", label: "Closed", icon: <X size={14} /> },
];

function timeAgo(iso?: string): string {
  if (!iso) return "—";
  const diff = Date.now() - new Date(iso).getTime();
  const mins = Math.floor(diff / 60000);
  if (mins < 1) return "Just now";
  if (mins < 60) return `${mins}m ago`;
  const hrs = Math.floor(mins / 60);
  if (hrs < 24) return `${hrs}h ago`;
  return `${Math.floor(hrs / 24)}d ago`;
}

function normalizeFilter(value: string | null): AdminChatFilter {
  return FILTER_OPTIONS.some((option) => option.value === value)
    ? (value as AdminChatFilter)
    : "all";
}

export default function AdminChatView() {
  const { showToast } = useToast();
  const pathname = usePathname();
  const router = useRouter();
  const searchParams = useSearchParams();

  const filter = normalizeFilter(searchParams.get("filter"));
  const search = readStringParam(searchParams.get("q") ?? searchParams.get("search"));
  const page = readPositiveIntParam(searchParams.get("page"), 1);

  const [searchInput, setSearchInput] = useState(search);
  const [items, setItems] = useState<AdminConvSummary[]>([]);
  const [total, setTotal] = useState(0);
  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState("");
  const [refreshKey, setRefreshKey] = useState(0);
  const [mutingChat, setMutingChat] = useState<AdminConvSummary | null>(null);
  const [muteReason, setMuteReason] = useState("");
  const [isMuting, setIsMuting] = useState(false);

  useEffect(() => {
    setSearchInput((prev) => (prev === search ? prev : search));
  }, [search]);

  const replaceQueryState = useCallback(
    (updates: Record<string, string | number | null | undefined>) => {
      const nextUrl = buildAdminRouteWithMergedQuery(pathname, searchParams, updates);
      const currentUrl = searchParams.toString() ? `${pathname}?${searchParams.toString()}` : pathname;
      if (nextUrl !== currentUrl) {
        void router.replace(nextUrl, { scroll: false });
      }
    },
    [pathname, router, searchParams]
  );

  useEffect(() => {
    const canonicalUrl = ADMIN_UI_ROUTES.chat({
      filter: filter !== "all" ? filter : undefined,
      q: search || undefined,
      page: page > 1 ? page : undefined,
    });
    const currentUrl = searchParams.toString() ? `${pathname}?${searchParams.toString()}` : pathname;
    if (canonicalUrl !== currentUrl) {
      void router.replace(canonicalUrl, { scroll: false });
    }
  }, [filter, page, pathname, router, search, searchParams]);

  useEffect(() => {
    const timeoutId = window.setTimeout(() => {
      if (searchInput === search) return;
      replaceQueryState({ q: searchInput || null, search: null, page: null });
    }, 250);

    return () => window.clearTimeout(timeoutId);
  }, [replaceQueryState, search, searchInput]);

  useEffect(() => {
    void (async () => {
      try {
        setIsLoading(true);
        setError("");
        const res = await fetchAdminChats({ filter, q: search, page, limit: 20 });
        setItems(res.data ?? []);
        setTotal(res.total ?? 0);
      } catch (e) {
        setError(e instanceof Error ? e.message : "Failed to load chats");
      } finally {
        setIsLoading(false);
      }
    })();
  }, [filter, page, refreshKey, search]);

  const refresh = () => setRefreshKey((k) => k + 1);

  const handleMute = async (id: string, reason?: string) => {
    try {
      setIsMuting(true);
      await adminMuteChat(id, reason || undefined);
      showToast("Conversation muted", "success");
      setMutingChat(null);
      setMuteReason("");
      refresh();
    } catch (e) {
      showToast(e instanceof Error ? e.message : "Failed to mute", "error");
    } finally {
      setIsMuting(false);
    }
  };

  const handleExport = async (id: string) => {
    try {
      const data = await adminExportChat(id);
      const blob = new Blob([JSON.stringify(data, null, 2)], { type: "application/json" });
      const url = URL.createObjectURL(blob);
      const anchor = document.createElement("a");
      anchor.href = url;
      anchor.download = `chat_${id}.json`;
      anchor.click();
      URL.revokeObjectURL(url);
    } catch {
      showToast("Export failed", "error");
    }
  };

  const totalPages = Math.ceil(total / 20);

  return (
    <AdminPageShell
      headerVariant="compact"
      title="Chat Moderation"
      actions={
        <button
          type="button"
          onClick={refresh}
          className="inline-flex items-center gap-2 rounded-lg border border-slate-200 bg-white px-3 py-2 text-sm font-medium text-slate-700 hover:bg-slate-50"
        >
          <RefreshCcw size={14} /> Refresh
        </button>
      }
    >
      <div className="flex min-h-0 flex-1 flex-col gap-3">
        <div className="flex flex-wrap items-center gap-2">
          {FILTER_OPTIONS.map((option) => (
            <button
              key={option.value}
              type="button"
              onClick={() => replaceQueryState({ filter: option.value !== "all" ? option.value : null, page: null })}
              className={`inline-flex items-center gap-1.5 rounded-full px-3 py-1.5 text-xs font-medium transition-colors ${
                filter === option.value
                  ? "bg-sky-600 text-white"
                  : "border border-slate-200 bg-white text-slate-600 hover:bg-slate-50"
              }`}
            >
              {option.icon}
              {option.label}
            </button>
          ))}
          <div className="relative ml-auto">
            <Search size={14} className="absolute left-2.5 top-1/2 -translate-y-1/2 text-slate-400" />
            <input
              value={searchInput}
              onChange={(event) => setSearchInput(event.target.value)}
              onKeyDown={(event) => {
                if (event.key === "Enter") {
                  replaceQueryState({ q: searchInput || null, search: null, page: null });
                }
              }}
              placeholder="Search buyer, seller, ad, or conversation ID"
              className="rounded-lg border border-slate-200 bg-slate-50 py-1.5 pl-7 pr-3 text-sm focus:outline-none focus:ring-2 focus:ring-sky-200"
            />
          </div>
        </div>

        {error && (
          <div className="rounded-lg border border-red-100 bg-red-50 p-3 text-sm text-red-600">
            {error}
          </div>
        )}

        <div className="overflow-hidden rounded-xl border border-slate-200 bg-white">
          <table className="w-full text-sm">
            <thead className="border-b border-slate-100 bg-slate-50 text-xs font-semibold text-slate-500">
              <tr>
                <th className="px-4 py-3 text-left">Buyer</th>
                <th className="px-4 py-3 text-left">Seller</th>
                <th className="px-4 py-3 text-left">Ad</th>
                <th className="px-4 py-3 text-left">Last Message</th>
                <th className="px-4 py-3 text-left">Status</th>
                <th className="px-4 py-3 text-left">Updated</th>
                <th className="px-4 py-3 text-left">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {isLoading ? (
                [...Array(5)].map((_, rowIndex) => (
                  <tr key={rowIndex}>
                    {[...Array(7)].map((_, cellIndex) => (
                      <td key={cellIndex} className="px-4 py-3">
                        <div className="h-4 animate-pulse rounded bg-slate-100" />
                      </td>
                    ))}
                  </tr>
                ))
              ) : items.length === 0 ? (
                <tr>
                  <td colSpan={7} className="px-4 py-8 text-center text-slate-400">
                    No chats found for this filter.
                  </td>
                </tr>
              ) : (
                items.map((conv) => (
                  <tr key={conv.id} className="transition-colors hover:bg-slate-50">
                    <td className="px-4 py-3 font-medium text-slate-800">{conv.buyerName}</td>
                    <td className="px-4 py-3 text-slate-600">{conv.sellerName}</td>
                    <td className="max-w-[160px] truncate px-4 py-3 text-slate-600" title={conv.adTitle}>
                      {conv.adTitle}
                    </td>
                    <td className="max-w-[200px] truncate px-4 py-3 text-slate-500" title={conv.lastMessage}>
                      {conv.lastMessage ?? "—"}
                    </td>
                    <td className="px-4 py-3">
                      {conv.isBlocked ? (
                        <span className="rounded-full bg-red-100 px-2 py-0.5 text-xs font-semibold text-red-700">Blocked</span>
                      ) : conv.isAdClosed ? (
                        <span className="rounded-full bg-amber-100 px-2 py-0.5 text-xs font-semibold text-amber-700">Closed</span>
                      ) : (
                        <span className="rounded-full bg-emerald-100 px-2 py-0.5 text-xs font-semibold text-emerald-700">Active</span>
                      )}
                    </td>
                    <td className="whitespace-nowrap px-4 py-3 text-slate-400">{timeAgo(conv.updatedAt)}</td>
                    <td className="px-4 py-3">
                      <div className="flex items-center gap-2">
                        <button
                          type="button"
                          onClick={() => void router.push(ADMIN_UI_ROUTES.chat({ q: conv.id }))}
                          className="text-sky-600 hover:underline text-xs font-medium"
                        >
                          Locate
                        </button>
                        {!conv.isBlocked && (
                          <button
                            type="button"
                            onClick={() => {
                              setMuteReason("");
                              setMutingChat(conv);
                            }}
                            className="text-amber-600 hover:underline text-xs font-medium"
                          >
                            Mute
                          </button>
                        )}
                        <button
                          type="button"
                          onClick={() => handleExport(conv.id)}
                          className="text-slate-500 hover:underline text-xs font-medium"
                        >
                          Export
                        </button>
                      </div>
                    </td>
                  </tr>
                ))
              )}
            </tbody>
          </table>
        </div>

        {totalPages > 1 && (
          <div className="flex items-center justify-between text-sm text-slate-500">
            <span>{total} total conversations</span>
            <div className="flex items-center gap-2">
              <button
                type="button"
                disabled={page <= 1}
                onClick={() => replaceQueryState({ page: page - 1 > 1 ? page - 1 : null })}
                className="rounded-lg border border-slate-200 px-3 py-1.5 hover:bg-slate-50 disabled:opacity-40"
              >
                Previous
              </button>
              <span className="font-medium">
                {page} / {totalPages}
              </span>
              <button
                type="button"
                disabled={page >= totalPages}
                onClick={() => replaceQueryState({ page: page + 1 })}
                className="rounded-lg border border-slate-200 px-3 py-1.5 hover:bg-slate-50 disabled:opacity-40"
              >
                Next
              </button>
            </div>
          </div>
        )}
      </div>

      <div
        className={`fixed inset-0 z-50 flex items-center justify-center bg-slate-900/40 p-4 transition-all ${
          mutingChat ? "opacity-100 backdrop-blur-sm" : "pointer-events-none opacity-0"
        }`}
      >
        <div className="w-full max-w-md rounded-2xl bg-white p-6 shadow-2xl">
          <div className="mb-4 flex items-center gap-3">
            <div className="flex h-10 w-10 items-center justify-center rounded-full bg-amber-100 text-amber-600">
              <AlertTriangle size={20} />
            </div>
            <div>
              <h3 className="text-lg font-bold text-slate-800">Mute Conversation</h3>
              <p className="text-sm text-slate-500">Silence this chat for all participants.</p>
            </div>
          </div>

          <div className="space-y-4">
            <div>
              <label className="mb-1.5 block text-xs font-bold uppercase tracking-wider text-slate-400">
                Reason for Muting (Optional)
              </label>
              <textarea
                value={muteReason}
                onChange={(e) => setMuteReason(e.target.value)}
                placeholder="e.g. Offensive language, Spam..."
                className="w-full min-h-[80px] rounded-lg border border-slate-200 bg-slate-50 p-3 text-sm focus:outline-none focus:ring-2 focus:ring-sky-200"
              />
            </div>

            <div className="flex justify-end gap-3">
              <button
                type="button"
                onClick={() => setMutingChat(null)}
                className="rounded-lg px-4 py-2 text-sm font-medium text-slate-600 hover:bg-slate-100"
              >
                Cancel
              </button>
              <button
                type="button"
                disabled={isMuting}
                onClick={() => mutingChat && handleMute(mutingChat.id, muteReason)}
                className="inline-flex items-center gap-2 rounded-lg bg-amber-600 px-4 py-2 text-sm font-semibold text-white hover:bg-amber-700 disabled:opacity-50"
              >
                {isMuting && <RefreshCcw size={14} className="animate-spin" />}
                Confirm Mute
              </button>
            </div>
          </div>
        </div>
      </div>
    </AdminPageShell>
  );
}

