"use client";

import { useEffect, useMemo, useRef, useState } from "react";
import Link from "next/link";
import { Search } from "lucide-react";
import {
    EMPTY_ADMIN_SEARCH_STATE,
    searchAdminRecords,
    type AdminSearchBucket,
    type AdminSearchItem,
} from "@/lib/api/adminSearch";

const SECTION_LABELS: Record<AdminSearchBucket, string> = {
    users: "Users",
    ads: "Listings",
    businesses: "Businesses",
    reports: "Reports",
    transactions: "Transactions",
};

export function AdminGlobalSearch({ autoFocus, onClose }: { autoFocus?: boolean; onClose?: () => void }) {
    const [query, setQuery] = useState("");
    const [results, setResults] = useState(EMPTY_ADMIN_SEARCH_STATE);
    const [isOpen, setIsOpen] = useState(false);
    const [loading, setLoading] = useState(false);
    const containerRef = useRef<HTMLDivElement>(null);

    useEffect(() => {
        const onClickOutside = (event: MouseEvent) => {
            if (containerRef.current && !containerRef.current.contains(event.target as Node)) {
                setIsOpen(false);
            }
        };
        document.addEventListener("mousedown", onClickOutside);
        return () => document.removeEventListener("mousedown", onClickOutside);
    }, []);

    useEffect(() => {
        const trimmed = query.trim();
        if (trimmed.length < 2) {
            setResults(EMPTY_ADMIN_SEARCH_STATE);
            setLoading(false);
            return;
        }

        let cancelled = false;
        setLoading(true);
        const timer = setTimeout(async () => {
            try {
                const nextState = await searchAdminRecords(trimmed);
                if (cancelled) return;
                setResults(nextState);
            } catch {
                if (!cancelled) {
                    setResults(EMPTY_ADMIN_SEARCH_STATE);
                }
            } finally {
                if (!cancelled) {
                    setLoading(false);
                }
            }
        }, 250);

        return () => {
            cancelled = true;
            clearTimeout(timer);
        };
    }, [query]);

    const sections = useMemo(
        () =>
            (Object.entries(results) as Array<[AdminSearchBucket, AdminSearchItem[]]>).filter(([, items]) => items.length > 0),
        [results]
    );

    return (
        <div className="relative max-w-xl flex-1" ref={containerRef}>
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
            <input
                type="text"
                autoFocus={autoFocus}
                value={query}
                onChange={(event) => {
                    setQuery(event.target.value);
                    setIsOpen(true);
                }}
                onKeyDown={(e) => {
                    if (e.key === "Escape" && onClose) onClose();
                }}
                onFocus={() => setIsOpen(true)}
                placeholder="Search users, listings, businesses, reports, and transactions"
                className="w-full rounded-xl border border-slate-200 bg-slate-50/80 py-2.5 pl-10 pr-4 text-sm text-slate-700 shadow-sm transition-all focus:outline-none focus:ring-2 focus:ring-sky-200"
            />

            {isOpen && query.trim().length >= 2 && (
                <div className="absolute inset-x-0 top-full z-50 mt-2 max-h-[28rem] overflow-y-auto rounded-2xl border border-slate-200 bg-white p-3 shadow-2xl">
                    {loading && sections.length === 0 ? (
                        <div className="px-3 py-6 text-sm text-slate-500">Searching…</div>
                    ) : sections.length > 0 ? (
                        <div className="space-y-4">
                            {sections.map(([bucket, items]) => (
                                <div key={bucket} className="space-y-2">
                                    <p className="px-2 text-[10px] font-bold uppercase tracking-[0.14em] text-slate-400">
                                        {SECTION_LABELS[bucket]}
                                    </p>
                                    <div className="space-y-1">
                                        {items.map((item) => (
                                            <Link
                                                key={`${bucket}-${item.id}`}
                                                href={item.href}
                                                onClick={() => setIsOpen(false)}
                                                className="block rounded-xl px-3 py-2 hover:bg-slate-50"
                                            >
                                                <p className="text-sm font-medium text-slate-900">{item.label}</p>
                                                <p className="text-xs text-slate-500">{item.meta}</p>
                                            </Link>
                                        ))}
                                    </div>
                                </div>
                            ))}
                        </div>
                    ) : (
                        <div className="px-3 py-6 text-sm text-slate-500">No matching admin records found.</div>
                    )}
                </div>
            )}
        </div>
    );
}

"use client";

import { Check, ExternalLink, MapPin, Pause, Phone, Play, RefreshCw, User, X } from "lucide-react";
import Link from "next/link";
import type { ModerationItem } from "./moderationTypes";
import { MODERATION_STATUS_BADGES, MODERATION_STATUS_LABELS } from "./moderationStatus";
import { resolveLocationDisplay } from "@/lib/location/display";
import { getListingAttribute, getListingPresentation, getListingPriceSummary } from "./listingPresentation";
import type { ListingTypeValue } from "@esparex/shared/enums/listingType";
import {
    Dialog,
    DialogContent,
    DialogDescription,
    DialogTitle,
} from "@/components/ui/dialog";

type ViewAdModalProps = {
    open: boolean;
    ad: ModerationItem | null;
    listingType?: ListingTypeValue;
    loading?: boolean;
    error?: string;
    onClose: () => void;
    onApprove: (adId: string) => Promise<void> | void;
    onReject: (adId: string) => void;
    onDeactivate: (adId: string) => Promise<void> | void;
    onActivate: (adId: string) => Promise<void> | void;
    onBlockSeller: (sellerId: string) => Promise<void> | void;
    onExtend?: (adId: string) => Promise<void> | void;
};

const IMAGE_FALLBACK = "https://placehold.co/800x600/png?text=No+Image";

export function ViewAdModal({
    open,
    ad,
    listingType,
    loading,
    error,
    onClose,
    onApprove,
    onReject,
    onDeactivate,
    onActivate,
    onBlockSeller,
    onExtend,
}: ViewAdModalProps) {
    const locationDisplay = ad
        ? resolveLocationDisplay({
            locationLabel: ad.locationLabel,
            coordinates: ad.locationCoordinates,
            fallbackDisplay: "Location not provided",
            emptyText: "Location not provided",
        })
        : "Location not provided";
    const effectiveListingType = listingType || ad?.listingType;
    const presentation = getListingPresentation(effectiveListingType);
    const attribute = ad ? getListingAttribute(ad, effectiveListingType) : null;

    return (
        <Dialog open={open} onOpenChange={(nextOpen) => { if (!nextOpen) onClose(); }}>
            <DialogContent
                className="max-w-4xl w-full flex max-h-[92dvh] flex-col bg-white overflow-hidden rounded-2xl border-none p-0"
                hideClose
            >
                <div className="flex items-center justify-between shrink-0 border-b border-slate-100 px-6 py-4">
                    <div>
                        <p className="text-[11px] font-semibold uppercase tracking-widest text-slate-400">Moderation</p>
                        <DialogTitle className="text-lg font-bold text-slate-900 mt-0.5">{presentation.modalTitle}</DialogTitle>
                    </div>
                    <button
                        type="button"
                        onClick={onClose}
                        className="h-9 w-9 flex items-center justify-center rounded-xl text-slate-400 hover:bg-slate-100 hover:text-slate-700 transition-colors shrink-0"
                        aria-label="Close"
                    >
