"use client";

import { useEffect, useState, type ReactNode } from "react";
import type { LucideIcon } from "lucide-react";
import { Ban, CheckCircle2, PlayCircle, Shield } from "lucide-react";
import {
    Dialog,
    DialogContent,
    DialogDescription,
    DialogHeader,
    DialogTitle,
} from "@/components/ui/dialog";
import {
    getUserDisplayName,
    type ManagedUser,
    type UserActionType,
} from "@/components/system/users/userManagement";

interface UserActionDialogProps {
    open: boolean;
    user: ManagedUser | null;
    actionType: UserActionType;
    isSubmitting: boolean;
    onClose: () => void;
    onConfirm: (reason: string) => Promise<void> | void;
}

type ActionPresentation = {
    title: string;
    description: string;
    helper: ReactNode;
    confirmLabel: string;
    submittingLabel: string;
    icon: LucideIcon;
    headerClassName: string;
    actionClassName: string;
    requiresReason: boolean;
};

const ACTION_PRESENTATION: Record<UserActionType, ActionPresentation> = {
    suspend: {
        title: "Suspend User",
        description: "You are about to suspend",
        helper: "Provide a clear reason so support and audit logs can explain the restriction.",
        confirmLabel: "Confirm Suspension",
        submittingLabel: "Suspending...",
        icon: Shield,
        headerClassName: "border-amber-100 bg-amber-50 text-amber-900",
        actionClassName: "bg-amber-600 hover:bg-amber-700",
        requiresReason: true,
    },
    ban: {
        title: "Block User",
        description: "You are about to block",
        helper: "Provide a clear reason so support and audit logs can explain the restriction.",
        confirmLabel: "Confirm Block",
        submittingLabel: "Blocking...",
        icon: Ban,
        headerClassName: "border-red-100 bg-red-50 text-red-900",
        actionClassName: "bg-red-600 hover:bg-red-700",
        requiresReason: true,
    },
    activate: {
        title: "Reactivate Account",
        description: "You are about to reactivate",
        helper: "This will restore account access and clear the user back to an active lifecycle state.",
        confirmLabel: "Reactivate Account",
        submittingLabel: "Reactivating...",
        icon: PlayCircle,
        headerClassName: "border-emerald-100 bg-emerald-50 text-emerald-900",
        actionClassName: "bg-emerald-600 hover:bg-emerald-700",
        requiresReason: false,
    },
    verify: {
        title: "Verify User",
        description: "You are about to verify",
        helper: "This marks the account as trusted at the admin level.",
        confirmLabel: "Verify User",
        submittingLabel: "Verifying...",
        icon: CheckCircle2,
        headerClassName: "border-emerald-100 bg-emerald-50 text-emerald-900",
        actionClassName: "bg-emerald-600 hover:bg-emerald-700",
        requiresReason: false,
    },
    unverify: {
        title: "Revoke Verification",
        description: "You are about to remove verification from",
        helper: "This will remove the account's verified flag without changing its active/suspended state.",
        confirmLabel: "Revoke Verification",
        submittingLabel: "Updating...",
        icon: Shield,
        headerClassName: "border-slate-200 bg-slate-50 text-slate-900",
        actionClassName: "bg-slate-900 hover:bg-slate-800",
        requiresReason: false,
    },
};

export function UserActionDialog({
    open,
    user,
    actionType,
    isSubmitting,
    onClose,
    onConfirm,
}: UserActionDialogProps) {
    const [reason, setReason] = useState("");

    useEffect(() => {
        if (open) {
            setReason("");
        }
    }, [open, actionType, user?.id]);

    if (!user) {
        return null;
    }

    const presentation = ACTION_PRESENTATION[actionType];
    const Icon = presentation.icon;
    const canSubmit = !presentation.requiresReason || Boolean(reason.trim());

    return (
        <Dialog open={open} onOpenChange={(nextOpen) => { if (!nextOpen && !isSubmitting) onClose(); }}>
            <DialogContent className="max-w-md overflow-hidden rounded-2xl p-0">
                <DialogHeader className={`border-b p-6 ${presentation.headerClassName}`}>
                    <div className="flex items-center gap-3">
                        <div className="flex h-10 w-10 items-center justify-center rounded-xl bg-white/60">
                            <Icon size={20} />
                        </div>
                        <div>
                            <DialogTitle className="text-base font-bold text-slate-900">
                                {presentation.title}
                            </DialogTitle>
                            <DialogDescription className="mt-0.5 text-xs text-slate-600">
                                {presentation.description}{" "}
                                <span className="font-semibold text-slate-800">
                                    {getUserDisplayName(user)}
                                </span>.
                            </DialogDescription>
                        </div>
                    </div>
                </DialogHeader>

                <div className="space-y-4 p-6">
                    <div className="rounded-lg border border-slate-200 bg-slate-50 p-3 text-xs text-slate-600">
                        {presentation.helper}
                    </div>

                    {presentation.requiresReason ? (
                        <div>
                            <label className="mb-2 block text-sm font-semibold text-slate-700">
                                Reason for Action <span className="text-red-500">*</span>
                            </label>
                            <textarea
                                className="min-h-[100px] w-full rounded-lg border border-slate-300 p-3 text-sm focus:outline-none focus:ring-2 focus:ring-sky-200"
                                placeholder="Explain why this account is being actioned to maintain the audit log..."
                                value={reason}
                                onChange={(event) => setReason(event.target.value)}
                                disabled={isSubmitting}
                            />
                        </div>
                    ) : null}

                    <p className="text-sm text-slate-500">
                        Are you sure you wish to proceed? This will be logged permanently in the
                        system audit trail.
                    </p>

                    <div className="flex items-center gap-3">
                        <button
                            onClick={onClose}
                            className="flex-1 rounded-lg bg-slate-100 px-4 py-2 font-bold text-slate-700 transition-colors hover:bg-slate-200"
                            disabled={isSubmitting}
                        >
                            Cancel
                        </button>
                        <button
                            onClick={() => void onConfirm(reason.trim())}
                            disabled={isSubmitting || !canSubmit}
                            className={`flex-1 rounded-lg px-4 py-2 font-bold text-white transition-colors disabled:cursor-not-allowed disabled:opacity-50 ${presentation.actionClassName}`}
                        >
                            {isSubmitting ? presentation.submittingLabel : presentation.confirmLabel}
                        </button>
                    </div>
                </div>
            </DialogContent>
        </Dialog>
    );
}

"use client";

import React, { useRef } from "react";
import { useVirtualizer } from "@tanstack/react-virtual";
import { ArrowUpDown } from "lucide-react";
import { DataTableToolbar } from "./DataTableToolbar";
import { DataTableBody } from "./DataTableBody";
import { DataTablePagination } from "./DataTablePagination";

export interface ColumnDef<T> {
    header: React.ReactNode;
    accessorKey?: keyof T;
    cell?: (item: T) => React.ReactNode;
    className?: string;
    id?: string;
    sortable?: boolean;
    exportValue?: (item: T) => string | number | null | undefined;
    defaultVisible?: boolean;
}

interface PaginationProps {
    currentPage: number;
    totalPages: number;
    totalItems: number;
    pageSize: number;
    onPageChange: (page: number) => void;
}

interface DataTableProps<T> {
    data: T[];
    columns: ColumnDef<T>[];
    isLoading?: boolean;
    emptyMessage?: string;
    onRowClick?: (item: T) => void;
    pagination?: PaginationProps;
    viewportClassName?: string;
    toolbar?: React.ReactNode;
    selectedCount?: number;
    bulkActions?: React.ReactNode;
    enableColumnVisibility?: boolean;
    enableCsvExport?: boolean;
    csvFileName?: string;
    onExportCsv?: () => void;
    sortState?: { columnId: string; direction: "asc" | "desc" } | null;
    onSortChange?: (columnId: string) => void;
    columnVisibility?: Record<string, boolean>;
    onColumnVisibilityChange?: (visibility: Record<string, boolean>) => void;
    hideColumnVisibilityButton?: boolean;
}

export function DataTable<T extends { id: string | number }>({
    data,
    columns,
    isLoading,
    emptyMessage = "No data found",
    onRowClick,
    pagination,
    viewportClassName,
    toolbar,
    selectedCount = 0,
    bulkActions,
    enableColumnVisibility = false,
    enableCsvExport = false,
    csvFileName = "export.csv",
    onExportCsv,
    sortState,
    onSortChange,
    columnVisibility: controlledColumnVisibility,
    onColumnVisibilityChange,
    hideColumnVisibilityButton = false,
}: DataTableProps<T>) {
    const loadingRows = [1, 2, 3, 4, 5];

    const { currentPage = 1, totalPages = 1, totalItems = data.length, pageSize = 20, onPageChange } = pagination || {};
    const startItem = (currentPage - 1) * pageSize + 1;
    const endItem = Math.min(currentPage * pageSize, totalItems);

    const parentRef = useRef<HTMLDivElement>(null);
    const [internalColumnVisibility, setInternalColumnVisibility] = React.useState<Record<string, boolean>>(() =>
        Object.fromEntries(
            columns.map((column, index) => [
                column.id || String(column.accessorKey || index),
                column.defaultVisible !== false,
            ])
        )
    );

    const columnVisibility = controlledColumnVisibility ?? internalColumnVisibility;
    const setColumnVisibility = (updater: Record<string, boolean> | ((prev: Record<string, boolean>) => Record<string, boolean>)) => {
        if (onColumnVisibilityChange) {
            const nextValue = typeof updater === "function" ? updater(columnVisibility) : updater;
            onColumnVisibilityChange(nextValue);
        } else {
            setInternalColumnVisibility(updater);
        }
    };


    const rowVirtualizer = useVirtualizer({
        count: data.length,
        getScrollElement: () => parentRef.current,
        estimateSize: () => 56,
        overscan: 5,
    });

    const virtualItems = rowVirtualizer.getVirtualItems();
    const firstVirtualItem = virtualItems[0];
    const lastVirtualItem = virtualItems.length > 0 ? virtualItems[virtualItems.length - 1] : undefined;
    const visibleColumns = columns.filter((column, index) => {
        const key = column.id || String(column.accessorKey || index);
        return columnVisibility[key] !== false;
    });

    const exportCsv = () => {
        if (onExportCsv) {
            onExportCsv();
            return;
        }

        const headers = visibleColumns.map((column) => column.header);
        const rows = data.map((item) =>
            visibleColumns.map((column) => {
                const value = column.exportValue
                    ? column.exportValue(item)
                    : column.accessorKey
                        ? item[column.accessorKey]
                        : "";
                const normalized = value == null ? "" : String(value).replace(/"/g, '""');
                return `"${normalized}"`;
            })
        );

        const csv = [headers.join(","), ...rows.map((row) => row.join(","))].join("\n");
        const blob = new Blob([csv], { type: "text/csv;charset=utf-8;" });
        const url = URL.createObjectURL(blob);
        const link = document.createElement("a");
        link.href = url;
        link.download = csvFileName;
        link.click();
        URL.revokeObjectURL(url);
    };

    return (
        <div className="w-full flex-col overflow-hidden rounded-xl border border-slate-200 bg-white shadow-sm">
            {isLoading ? (
                <div className="w-full bg-white border border-slate-200 rounded-xl overflow-hidden animate-pulse">
                    <div className="h-12 bg-slate-50 border-b border-slate-100" />
                    {loadingRows.map((i) => (
                        <div key={i} className="h-16 border-b border-slate-50 mx-4" />
                    ))}
                </div>
            ) : (
                <>
                    <DataTableToolbar
                        toolbar={toolbar}
                        bulkActions={bulkActions}
                        selectedCount={selectedCount}
                        enableColumnVisibility={enableColumnVisibility}
                        hideColumnVisibilityButton={hideColumnVisibilityButton}
                        columns={columns}
                        columnVisibility={columnVisibility}
                        setColumnVisibility={setColumnVisibility}
                        enableCsvExport={enableCsvExport}
                        exportCsv={exportCsv}
                    />
                    <div
                        ref={parentRef}
                        className={`custom-scrollbar overflow-auto max-h-[70vh] ${viewportClassName || ""}`}
                    >
                        <table className="w-full text-left text-sm border-collapse min-w-[600px]">
                            <thead className="bg-slate-50 text-slate-500 border-b border-slate-200 sticky top-0 z-10">
                                <tr>
                                    {visibleColumns.map((col, idx) => (
                                        <th key={idx} className={`px-6 py-4 font-bold uppercase tracking-wider text-[10px] ${col.className || ""}`}>
                                            <button
                                                type="button"
                                                disabled={!col.sortable || !onSortChange}
                                                onClick={() => {
                                                    const columnId = col.id || String(col.accessorKey || idx);
                                                    if (col.sortable && onSortChange) onSortChange(columnId);
                                                }}
                                                className={`flex items-center gap-2 group transition-colors ${col.sortable && onSortChange ? "cursor-pointer hover:text-slate-900" : "cursor-default"}`}
                                                aria-label={col.sortable && onSortChange ? `Sort by ${col.header}` : undefined}
                                            >
                                                {col.header}
                                                <ArrowUpDown
                                                    size={12}
                                                    className={`transition-opacity ${
                                                        sortState && (col.id || String(col.accessorKey || idx)) === sortState.columnId
                                                            ? "opacity-100 text-slate-900"
                                                            : "opacity-0 group-hover:opacity-100"
                                                    }`}
                                                />
                                            </button>
                                        </th>
                                    ))}
                                </tr>
                            </thead>
                            <DataTableBody
                                data={data}
                                virtualItems={virtualItems}
                                firstVirtualItem={firstVirtualItem}
                                lastVirtualItem={lastVirtualItem}
                                visibleColumns={visibleColumns}
                                rowVirtualizer={rowVirtualizer}
                                emptyMessage={emptyMessage}
                                onRowClick={onRowClick}
                            />
                        </table>
                    </div>

                    <DataTablePagination
                        currentPage={currentPage}
                        totalPages={totalPages}
                        totalItems={totalItems}
                        startItem={startItem}
                        endItem={endItem}
                        dataLength={data.length}
                        onPageChange={onPageChange}
                    />
                </>
            )}
        </div>
    );
}

import React, { useState } from "react";
import { EyeOff, Download } from "lucide-react";

export interface DataTableToolbarProps<T> {
    toolbar?: React.ReactNode;
    bulkActions?: React.ReactNode;
    selectedCount: number;
    enableColumnVisibility: boolean;
    hideColumnVisibilityButton: boolean;
    columns: unknown[];
    columnVisibility: Record<string, boolean>;
    setColumnVisibility: (updater: Record<string, boolean> | ((prev: Record<string, boolean>) => Record<string, boolean>)) => void;
    enableCsvExport: boolean;
    exportCsv: () => void;
}

export function DataTableToolbar<T>({
    toolbar, bulkActions, selectedCount, enableColumnVisibility, hideColumnVisibilityButton,
    columns, columnVisibility, setColumnVisibility, enableCsvExport, exportCsv
}: DataTableToolbarProps<T>) {
    const [showColumnsMenu, setShowColumnsMenu] = useState(false);

    if (!toolbar && !bulkActions && !enableColumnVisibility && !enableCsvExport) {
        return null;
    }

    return (
        <div className="flex flex-wrap items-center justify-between gap-3 border-b border-slate-100 bg-slate-50/70 px-4 py-3">
            <div className="flex flex-wrap items-center gap-3">
                {toolbar}
                {bulkActions && selectedCount > 0 && (
                    <div className="flex flex-wrap items-center gap-2">
                        <span className="text-xs font-semibold uppercase tracking-[0.12em] text-slate-500">
                            {selectedCount} selected
                        </span>
                        {bulkActions}
                    </div>
                )}
            </div>
            <div className="flex items-center gap-2">
                {enableColumnVisibility && !hideColumnVisibilityButton && (
                    <div className="relative">
                        <button
                            type="button"
                            onClick={() => setShowColumnsMenu((prev) => !prev)}
                            className="inline-flex items-center gap-2 rounded-lg border border-slate-200 bg-white px-3 py-2 text-xs font-semibold text-slate-700 hover:bg-slate-50"
                            aria-label="Toggle column visibility menu"
                        >
                            <EyeOff size={14} /> Columns
                        </button>
                        {showColumnsMenu && (
                            <div className="absolute right-0 top-full z-20 mt-2 min-w-[220px] rounded-xl border border-slate-200 bg-white p-2 shadow-xl">
                                {columns.map((column, index) => {
                                    const key = column.id || String(column.accessorKey || index);
                                    return (
                                        <label key={key} className="flex items-center gap-2 rounded-lg px-2 py-2 text-sm text-slate-700 hover:bg-slate-50">
                                            <input
                                                type="checkbox"
                                                checked={columnVisibility[key] !== false}
                                                aria-label={`Toggle ${column.header} column`}
                                                onChange={(event) =>
                                                    setColumnVisibility((prev) => ({
                                                        ...prev,
                                                        [key]: event.target.checked,
                                                    }))
                                                }
                                            />
                                            <span>{column.header}</span>
                                        </label>
                                    );
                                })}
                            </div>
                        )}
                    </div>
                )}
                {enableCsvExport && (
                    <button
                        type="button"
                        onClick={exportCsv}
                        className="inline-flex items-center gap-2 rounded-lg border border-slate-200 bg-white px-3 py-2 text-xs font-semibold text-slate-700 hover:bg-slate-50"
                        aria-label="Export table as CSV"
                    >
                        <Download size={14} /> Export CSV
                    </button>
                )}
            </div>
        </div>
    );
}

