"use client";

import { createContext, useCallback, useContext, useEffect, useMemo, useRef, useState } from "react";
import { AdminApiError, adminFetch, setAdminAccessToken } from "@/lib/api/adminClient";
import { ADMIN_ROUTES } from "@/lib/api/routes";
import { parseAdminResponse } from "@/lib/api/parseAdminResponse";
import type { AdminUser } from "@/types/admin";

type LoginInput = {
  email: string;
  password: string;
  twoFactorCode?: string;
};

type AdminAuthState = {
  admin: AdminUser | null;
  loading: boolean;
  login: (input: LoginInput) => Promise<void>;
  logout: () => Promise<void>;
  refresh: () => Promise<void>;
};

const AdminAuthContext = createContext<AdminAuthState | undefined>(undefined);

function normalizeAdmin(payload: unknown): AdminUser | null {
  if (!payload || typeof payload !== "object") return null;
  const item = payload as Record<string, unknown>;
  const id = item.id || item._id;
  if (!id || typeof item.email !== "string" || typeof item.role !== "string") return null;
  return {
    id: String(id),
    email: item.email,
    role: item.role,
    firstName: typeof item.firstName === "string" ? item.firstName : undefined,
    lastName: typeof item.lastName === "string" ? item.lastName : undefined,
    permissions: Array.isArray(item.permissions) ? item.permissions.filter((p): p is string => typeof p === "string") : []
  };
}

export function AdminAuthProvider({ children }: { children: React.ReactNode }) {
  const [admin, setAdmin] = useState<AdminUser | null>(null);
  const [loading, setLoading] = useState(true);
  const authRequestSeq = useRef(0);

  const refresh = useCallback(async () => {
    const requestId = ++authRequestSeq.current;
    try {
      const result = await adminFetch<unknown>(ADMIN_ROUTES.ME);
      const parsed = parseAdminResponse<never, { admin?: AdminUser }>(result);
      const nextAdmin = normalizeAdmin(parsed.data?.admin);
      if (requestId === authRequestSeq.current) {
        setAdmin(nextAdmin);
      }
    } catch (error) {
      if (error instanceof AdminApiError && error.status === 401) {
        setAdminAccessToken(null);
      }
      if (requestId === authRequestSeq.current) {
        setAdmin(null);
      }
    } finally {
      if (requestId === authRequestSeq.current) {
        setLoading(false);
      }
    }
  }, []);

  useEffect(() => {
    void refresh();
  }, [refresh]);

  const login = useCallback(async (input: LoginInput) => {
    const requestId = ++authRequestSeq.current;
    setLoading(true);
    try {
      const result = await adminFetch<unknown>(ADMIN_ROUTES.LOGIN, {
        method: "POST",
        body: input
      });
      const parsed = parseAdminResponse<never, { admin?: AdminUser; accessToken?: string }>(result);
      const accessToken = typeof parsed.data?.accessToken === "string" ? parsed.data.accessToken : null;
      setAdminAccessToken(accessToken);

      let nextAdmin = normalizeAdmin(parsed.data?.admin);
      if (!nextAdmin) {
        const meResult = await adminFetch<unknown>(ADMIN_ROUTES.ME);
        const meParsed = parseAdminResponse<never, { admin?: AdminUser }>(meResult);
        nextAdmin = normalizeAdmin(meParsed.data?.admin);
      }

      if (!nextAdmin) throw new Error("Login succeeded but admin profile could not be loaded. Please try again.");
      if (requestId === authRequestSeq.current) {
        setAdmin(nextAdmin);
      }
    } catch (error) {
      setAdminAccessToken(null);
      throw error;
    } finally {
      if (requestId === authRequestSeq.current) {
        setLoading(false);
      }
    }
  }, []);

  const logout = useCallback(async () => {
    const requestId = ++authRequestSeq.current;
    setLoading(true);
    try {
      await adminFetch<never>(ADMIN_ROUTES.LOGOUT, { method: "POST" });
    } finally {
      setAdminAccessToken(null);
      if (requestId === authRequestSeq.current) {
        setAdmin(null);
        setLoading(false);
      }
    }
  }, []);

  const value = useMemo<AdminAuthState>(
    () => ({
      admin,
      loading,
      login,
      logout,
      refresh
    }),
    [admin, loading, login, logout, refresh]
  );

  return <AdminAuthContext.Provider value={value}>{children}</AdminAuthContext.Provider>;
}

export function useAdminAuth() {
  const ctx = useContext(AdminAuthContext);
  if (!ctx) {
    throw new Error("useAdminAuth must be used within AdminAuthProvider");
  }
  return ctx;
}

import { useCallback } from "react";
import { useToast } from "@/context/ToastContext";
import { parseAdminResponse } from "@/lib/api/parseAdminResponse";
import { useAdminCrudList, type AdminListPagination } from "@/hooks/useAdminCrudList";

type FilterValue = string | number | boolean | null | undefined;
type AdminCollectionFilters = Record<string, FilterValue>;

type AdminResponseLike = {
    success?: boolean;
    message?: string;
    payload?: {
        message?: unknown;
        error?: unknown;
        details?: Array<{ field?: unknown; message?: unknown }>;
    };
};

type MutationOptions = {
    successMessage: string;
    errorMessage: string;
    onSuccess?: () => Promise<void> | void;
};

interface UseAdminCatalogCollectionOptions<
    _T extends { id: string },
    F extends AdminCollectionFilters,
    CreatePayload,
    UpdatePayload = CreatePayload,
> {
    initialFilters: F;
    fetchList: (query: Record<string, string | number | boolean>) => Promise<AdminResponseLike>;
    listErrorMessage: string;
    createItem: (data: CreatePayload) => Promise<AdminResponseLike>;
    createSuccessMessage: string;
    createErrorMessage: string;
    updateItem: (id: string, data: UpdatePayload) => Promise<AdminResponseLike>;
    updateSuccessMessage: string;
    updateErrorMessage: string;
    deleteItem: (id: string) => Promise<AdminResponseLike>;
    deleteSuccessMessage: string;
    deleteErrorMessage: string;
    _deleteConfirmMessage?: string;
    deleteStrategy?: "filter" | "refresh";
    initialPagination?: Partial<AdminListPagination>;
}

import { AdminApiError } from "@/lib/api/adminClient";

export function extractAdminApiErrorMessage(error: unknown, fallback: string): string {
    return AdminApiError.resolveMessage(error, fallback);
}

export function buildAdminListQuery<F extends AdminCollectionFilters>(
    filters: F,
    pagination: { page: number; limit: number }
) {
    const query: Record<string, string | number | boolean> = {
        page: pagination.page,
        limit: pagination.limit,
    };

    Object.entries(filters).forEach(([key, value]) => {
        if (value === undefined || value === null || value === "" || value === "all") {
            return;
        }

        query[key] = value;
    });

    return query;
}

export async function fetchAdminCatalogPage<T, F extends AdminCollectionFilters>({
    filters,
    pagination,
    fetchList,
    errorMessage,
}: {
    filters: F;
    pagination: { page: number; limit: number };
    fetchList: (query: Record<string, string | number | boolean>) => Promise<AdminResponseLike>;
    errorMessage: string;
}) {
    const response = await fetchList(buildAdminListQuery(filters, pagination));
    if (!response.success) {
        return {
            items: [] as T[],
            error: response.message || errorMessage,
        };
    }

    const parsed = parseAdminResponse<T>(response);
    const items = parsed.items;

    return {
        items,
        pagination: parsed.pagination || {
            page: pagination.page,
            limit: pagination.limit,
            total: items.length,
            totalPages: 1,
        },
    };
}

export function useAdminCatalogCollection<
    T extends { id: string },
    F extends AdminCollectionFilters,
    CreatePayload,
    UpdatePayload = CreatePayload,
>({
    initialFilters,
    fetchList,
    listErrorMessage,
    createItem,
    createSuccessMessage,
    createErrorMessage,
    updateItem,
    updateSuccessMessage,
    updateErrorMessage,
    deleteItem,
    deleteSuccessMessage,
    deleteErrorMessage,
    _deleteConfirmMessage,
    deleteStrategy = "filter",
    initialPagination,
}: UseAdminCatalogCollectionOptions<T, F, CreatePayload, UpdatePayload>) {
    const { showToast } = useToast();

    const fetchPage = useCallback(
        (params: { filters: F; pagination: AdminListPagination }) =>
            fetchAdminCatalogPage<T, F>({
                filters: params.filters,
                pagination: params.pagination,
                fetchList,
                errorMessage: listErrorMessage,
            }),
        [fetchList, listErrorMessage]
    );

    const {
        items,
        setItems,
        loading,
        error,
        pagination,
        filters,
        setFilters,
        setPage,
        refresh,
    } = useAdminCrudList<T, F>({
        initialFilters,
        fetchPage,
        initialPagination,
    });

    const runAction = useCallback(
        async (
            operation: () => Promise<AdminResponseLike>,
            { successMessage, errorMessage, onSuccess }: MutationOptions
        ) => {
            try {
                const response = await operation();
                if (!response.success) {
                    showToast(response.message || errorMessage, "error");
                    return false;
                }

                showToast(successMessage, "success");
                if (onSuccess) {
                    await onSuccess();
                }
                return true;
            } catch (error) {
                showToast(extractAdminApiErrorMessage(error, errorMessage), "error");
                return false;
            }
        },
        [showToast]
    );

    const handleDelete = useCallback(
        async (id: string) => {
            return runAction(() => deleteItem(id), {
                successMessage: deleteSuccessMessage,
                errorMessage: deleteErrorMessage,
                onSuccess: async () => {
                    if (deleteStrategy === "filter") {
                        setItems((prev) => prev.filter((item) => item.id !== id));
                        return;
                    }

                    await refresh();
                },
            });
        },
        [
            deleteErrorMessage,
            deleteItem,
            deleteStrategy,
            deleteSuccessMessage,
            refresh,
            runAction,
            setItems,
        ]
    );

    const handleCreate = useCallback(
        async (data: CreatePayload) =>
            runAction(() => createItem(data), {
                successMessage: createSuccessMessage,
                errorMessage: createErrorMessage,
                onSuccess: async () => {
                    await refresh();
                },
            }),
        [createErrorMessage, createItem, createSuccessMessage, refresh, runAction]
    );

    const handleUpdate = useCallback(
        async (id: string, data: UpdatePayload) =>
            runAction(() => updateItem(id, data), {
                successMessage: updateSuccessMessage,
                errorMessage: updateErrorMessage,
                onSuccess: async () => {
                    await refresh();
                },
            }),
        [refresh, runAction, updateErrorMessage, updateItem, updateSuccessMessage]
    );

    return {
        items,
        setItems,
        loading,
        error,
        pagination,
        filters,
        setFilters,
        setPage,
        refresh,
        runAction,
        handleDelete,
        handleCreate,
        handleUpdate,
    };
}

