"use client";

import { useState, useRef, useLayoutEffect, useMemo, useEffect, type CSSProperties } from "react";
import { Check, Search, Loader2, Plus } from "@/icons/IconRegistry";
import { cn } from "@/components/ui/utils";
import { Input } from "@/components/ui/input";
import { Z_INDEX } from "@/lib/zIndexConfig";
import { usePostAd } from "@/components/user/post-ad/PostAdContext";
import type { DeviceModel } from "@/lib/api/user/masterData";
import { ensureModel } from "@/lib/api/user/masterData";

interface ModelSearchSelectProps {
    brandId: string;
    /** Display name of the selected brand — used for ensureModel when brandId is empty (custom brand). */
    brandName?: string;
    categoryId: string;
    /** Currently selected modelId or modelName */
    value: string;
    /** Human-readable display name for the current value — used when value is an ObjectId not in availableModels */
    modelDisplayName?: string;
    /** Called with (modelId, modelName) on selection */
    onChange: (modelId: string, modelName: string) => void;
    /**
     * Called after ensureModel creates a new brand record so the parent can
     * sync the pending brandId back into the form.
     */
    onBrandResolved?: (brandId: string, brandName: string) => void;
    disabled?: boolean;
    placeholder?: string;
    className?: string;
}

export function ModelSearchSelect({
    brandId,
    brandName = "",
    categoryId,
    value,
    modelDisplayName = "",
    onChange,
    onBrandResolved,
    disabled = false,
    placeholder = "Search model (e.g. iPhone 14 Pro)...",
    className,
}: ModelSearchSelectProps) {
    const { availableModels, loadModelsForBrand, setAvailableModels } = usePostAd();

    const [search, setSearch] = useState("");
    const [isEditing, setIsEditing] = useState(false);
    const [isLoading, setIsLoading] = useState(false);
    const [ensureError, setEnsureError] = useState<string | null>(null);
    const containerRef = useRef<HTMLDivElement>(null);
    const [dropdownStyle, setDropdownStyle] = useState<CSSProperties | null>(null);

    // Local selection state to bridge the gap during prop/context sync
    const [localSelection, setLocalSelection] = useState<{ id: string; name: string } | null>(null);

    // Resolve selected model name.
    // Priority: matched model in list > local tentative selection > explicit displayName > raw value (ObjectId fallback)
    const selectedModel = useMemo(() => {
        return availableModels.find(m => m.id === value || m._id === value);
    }, [availableModels, value]);

    const selectedName = selectedModel?.name || localSelection?.name || modelDisplayName || value || "";

    // Clear local selection once the catalog has actually picked up the new model
    useEffect(() => {
        if (localSelection && selectedModel) {
            // Success: the model is now officially in the catalog list
            setLocalSelection(null);
        }
    }, [selectedModel, localSelection]);

    // Debounced search logic
    useEffect(() => {
        if (!search || search.length < 2) return;

        const timer = setTimeout(async () => {
            setIsLoading(true);
            await loadModelsForBrand(brandId, categoryId, search);
            setIsLoading(false);
        }, 400);

        return () => clearTimeout(timer);
    }, [search, brandId, categoryId, loadModelsForBrand]);

    // Initial load of popular models
    useEffect(() => {
        if (brandId && !search) {
            loadModelsForBrand(brandId, categoryId);
        }
    }, [brandId, categoryId, loadModelsForBrand, search]);

    // Dropdown positioning
    useLayoutEffect(() => {
        if (!isEditing && !search) {
            setDropdownStyle(null);
            return;
        }
        const container = containerRef.current;
        if (!container) return;

        const calculate = () => {
            const rect = container.getBoundingClientRect();
            const spaceBelow = window.innerHeight - rect.bottom;
            setDropdownStyle({
                position: "fixed",
                top: rect.bottom + 4,
                left: rect.left,
                width: rect.width,
                maxHeight: Math.min(300, Math.max(spaceBelow - 8, 80)),
            });
        };

        calculate();
        window.addEventListener("scroll", calculate, true);
        window.addEventListener("resize", calculate);
        return () => {
            window.removeEventListener("scroll", calculate, true);
            window.removeEventListener("resize", calculate);
        };
    }, [isEditing, search]);

    const handleSelect = (model: DeviceModel) => {
        const id = String(model.id || model._id);
        const name = model.name;
        setLocalSelection({ id, name });
        onChange(id, name);
        setSearch("");
        setIsEditing(false);
    };

    const [isEnsuring, setIsEnsuring] = useState(false);

    const handleAddNew = async () => {
        const trimmed = search.trim();
        if (!trimmed || !categoryId) return;

        // Resolve brand identifier: prefer the display name, fall back to the DB id.
        const effectiveBrandName = brandName || brandId;
        if (!effectiveBrandName) return;

        setIsEnsuring(true);
        setEnsureError(null);
        try {
            const result = await ensureModel(categoryId, effectiveBrandName, trimmed);
            setLocalSelection({ id: result.id, name: result.name });
            onChange(result.id, result.name);

            // If a new pending brand was created, propagate its ID to the parent form.
            if (result.brandId && (!brandId || brandId !== result.brandId)) {
                onBrandResolved?.(result.brandId, brandName || effectiveBrandName);
            }

            // Push the new model into the catalog state immediately so the chip finds it.
            const newModel: DeviceModel = {
                id: result.id,
                _id: result.id,
                name: result.name,
                brandId: result.brandId || brandId,
                categoryId: categoryId,
                status: 'pending'
            };
            setAvailableModels([...availableModels, newModel]);
            // Success — close search mode
            setSearch("");
            setIsEditing(false);
        } catch (err) {
            // Surface the error so the user knows what happened and can retry.
            const msg = err instanceof Error ? err.message : "Failed to add model — please try again.";
            setEnsureError(msg);
            // Keep isEditing=true so the user's search text stays and they can retry.
        } finally {
            setIsEnsuring(false);
        }
    };

    // ── Selected State ──────────────────────────────────────────────────────
    if (selectedName && !isEditing) {
        return (
            <div className={cn(
                "flex h-12 items-center justify-between rounded-xl border border-slate-200 bg-slate-50 px-4 transition-all hover:bg-slate-100/50",
                className
            )}>
                <div className="flex items-center gap-2.5 min-w-0">
                    <Check className="w-4 h-4 text-green-600 shrink-0" />
                    <span className="truncate text-sm font-semibold text-foreground">{selectedName}</span>
                </div>
                {!disabled && (
                    <button
                        type="button"
                        onClick={() => setIsEditing(true)}
                        className="ml-2 shrink-0 text-xs font-bold text-primary hover:opacity-80 active:scale-95 transition-all"
                    >
                        Edit
                    </button>
                )}
            </div>
        );
    }

    // ── Search State ────────────────────────────────────────────────────────
    return (
        <div 
            className={cn("relative", className)} 
            ref={containerRef}
            style={{ zIndex: isEditing ? Z_INDEX.brandSearchBackdrop + 1 : undefined }}
        >
            <div className="relative group">
                <div className="absolute left-3.5 top-1/2 -translate-y-1/2 flex items-center gap-2 pointer-events-none">
                    {isLoading ? (
                        <Loader2 className="w-4 h-4 text-primary animate-spin" />
                    ) : (
                        <Search className="w-4 h-4 text-slate-400 group-focus-within:text-primary transition-colors" />
                    )}
                </div>
                <Input
                    autoFocus={isEditing}
                    value={search}
                    onChange={(e) => setSearch(e.target.value)}
                    onKeyDown={(e) => {
                        if (e.key === "Enter" && search.length >= 2) {
                            e.preventDefault();
                            handleAddNew();
                        }
                        if (e.key === "Escape") {
                            setIsEditing(false);
                            setSearch("");
                        }
                    }}
                    onFocus={() => setIsEditing(true)}
                    placeholder={placeholder}
                    disabled={disabled || isEnsuring}
                    className={cn(
                        "pl-10 pr-12 h-12 text-sm font-medium border-slate-200/80 rounded-xl transition-all",
                        "focus:ring-2 focus:ring-primary/10 focus:border-primary shadow-sm"
                    )}
                />
                {search.length >= 2 && !isLoading && (
                    <button
                        type="button"
                        onClick={handleAddNew}
                        disabled={isEnsuring}
                        className="absolute right-2 top-1/2 -translate-y-1/2 flex items-center justify-center w-8 h-8 rounded-full bg-primary/10 text-primary hover:bg-primary hover:text-white transition-all shadow-sm active:scale-95 disabled:opacity-60 disabled:cursor-wait"
                        title={`Add "${search}" as a new suggestion`}
                    >
                        {isEnsuring ? (
                            <Loader2 className="w-4 h-4 animate-spin" />
                        ) : (
                            <Plus className="w-5 h-5" />
                        )}
                    </button>
                )}
            </div>

            {ensureError && (
                <p className="mt-1 px-1 text-xs text-red-600 font-medium flex items-center gap-1">
                    <span>⚠</span> {ensureError}
                </p>
            )}

            {(isEditing || search) && dropdownStyle && (
                <>
                    <div
                        style={{ zIndex: Z_INDEX.brandSearchBackdrop }}
                        className="fixed inset-0"
                        onClick={() => {
                            setIsEditing(false);
                            setSearch("");
                        }}
                    />
                    <div
                        style={{ ...dropdownStyle, zIndex: Z_INDEX.selectContent }}
                        className="bg-white border border-slate-200 rounded-2xl shadow-2xl overflow-hidden flex flex-col animate-in fade-in slide-in-from-top-2 duration-200"
                    >
                        <div className="overflow-y-auto max-h-[280px] p-1.5 space-y-1">
                            {availableModels.length === 0 && !isLoading && search.length >= 2 ? (
                                <div className="py-8 px-5 flex flex-col items-center text-center animate-in fade-in zoom-in-95 duration-300">
                                    <div className="w-12 h-12 rounded-2xl bg-slate-50 flex items-center justify-center mb-4 border border-slate-100 shadow-sm">
                                        <Search className="w-5 h-5 text-slate-300" />
                                    </div>
                                    <h3 className="text-sm font-bold text-slate-700 mb-1">
                                        Model Not Found
                                    </h3>
                                    <p className="text-xs text-slate-400 font-medium leading-relaxed mb-6 max-w-[200px]">
                                        We couldn&apos;t find &ldquo;{search}&rdquo; in our catalog.
                                    </p>

                                    <button
                                        type="button"
                                        onClick={(e) => {
                                            e.preventDefault();
                                            handleAddNew();
                                        }}
                                        disabled={isEnsuring}
                                        className="w-full flex items-center justify-center gap-2 py-3 px-4 rounded-xl bg-primary text-white text-sm font-bold hover:bg-primary/90 transition-all active:scale-[0.97] shadow-md shadow-primary/20 disabled:opacity-70"
                                    >
                                        {isEnsuring ? (
                                            <Loader2 className="w-4 h-4 animate-spin" />
                                        ) : (
                                            <span className="text-lg leading-none">+</span>
                                        )}
                                        {isEnsuring ? "Adding..." : `Use "${search.trim()}"`}
                                    </button>
                                </div>
                            ) : availableModels.length === 0 && !isLoading && !search ? (
                                <div className="py-8 px-4 text-center text-sm text-slate-400 font-medium italic">
                                    Start typing to find your model...
                                </div>
                            ) : (
                                <>
                                    {availableModels.map((m) => (
                                        <button
                                            key={String(m.id || m._id)}
                                            type="button"
                                            onClick={() => handleSelect(m)}
                                            className="w-full px-4 py-3 text-left text-sm font-semibold text-slate-700 transition-all hover:bg-primary/5 hover:text-primary active:bg-primary/10 flex items-center justify-between group rounded-lg"
                                        >
                                            <span>{m.name}</span>
                                        </button>
                                    ))}

                                    {search.length >= 2 && !isLoading && (
                                        <button
                                            type="button"
                                            onClick={(e) => {
                                                e.preventDefault();
                                                handleAddNew();
                                            }}
                                            disabled={isEnsuring}
                                            className="w-full mt-1 p-3 flex items-center justify-center gap-2 border-t border-slate-50 text-xs font-bold text-primary hover:bg-slate-50 transition-colors disabled:opacity-60"
                                        >
                                            {isEnsuring ? <Loader2 className="w-3 h-3 animate-spin" /> : <span>+</span>}
                                            {isEnsuring ? "Adding..." : `Don't see it? Add "${search}"`}
                                        </button>
                                    )}
                                </>
                            )}
                        </div>
                    </div>
                </>
            )}
        </div>
    );
}

"use client";

import { useEffect, useState } from "react";
import { useMutation, useQueryClient } from "@tanstack/react-query";
import {
    Bell,
    Inbox,
} from "lucide-react";
import { usePathname, useRouter } from "next/navigation";

import { queryKeys } from "@/hooks/queries";
import { notificationApi, type Notification, type NotificationResponse } from "@/lib/api/user/notifications";
import { Button } from "@/components/ui/button";
import {
    DropdownMenu,
    DropdownMenuContent,
    DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu";
import { NotificationItemCard } from "@/components/user/NotificationItemCard";

type NotificationBellDropdownProps = {
    notificationsData?: NotificationResponse;
    unreadCount: number;
    onRefresh?: () => Promise<unknown>;
    variant?: "desktop" | "mobile";
};

const isExternalUrl = (href: string) => /^https?:\/\//i.test(href);

const resolveNotificationTarget = (href: string) => {
    if (typeof window === "undefined") {
        return {
            isExternal: isExternalUrl(href),
            href,
        };
    }

    try {
        const url = new URL(href, window.location.origin);
        const isExternal = url.origin !== window.location.origin;
        return {
            isExternal,
            href: isExternal ? url.toString() : `${url.pathname}${url.search}${url.hash}`,
        };
    } catch {
        return {
            isExternal: isExternalUrl(href),
            href: href.startsWith("/") ? href : `/${href.replace(/^\.?\//, "")}`,
        };
    }
};

const sortNotifications = (items: Notification[]) =>
    [...items].sort((a, b) => {
        // Just sort by date, keeping the list simple
        return new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime();
    });

export function NotificationBellDropdown({
    notificationsData,
    unreadCount,
    onRefresh,
    variant = "desktop",
}: NotificationBellDropdownProps) {
    const router = useRouter();
    const pathname = usePathname();
    const queryClient = useQueryClient();
    const [open, setOpen] = useState(false);

    const notifications = sortNotifications(
        Array.isArray(notificationsData?.notifications) ? notificationsData.notifications : []
    );

    useEffect(() => {
        setOpen(false);
    }, [pathname]);

    const syncNotificationCaches = (
        updater: (current: NotificationResponse) => NotificationResponse
    ) => {
        queryClient.setQueriesData<NotificationResponse | undefined>(
            { queryKey: queryKeys.notifications.all },
            (current) => {
                if (!current) return current;
                return updater(current);
            }
        );
    };

    const markReadMutation = useMutation({
        mutationFn: (id: string) => notificationApi.markRead(id),
        onSuccess: (_response, id) => {
            const now = new Date().toISOString();
            syncNotificationCaches((current) => {
                const target = current.notifications.find((item) => item.id === id);
                return {
                    ...current,
                    notifications: current.notifications.map((item) =>
                        item.id === id ? { ...item, isRead: true, readAt: now } : item
                    ),
                    unreadCount: target && !target.isRead ? Math.max(0, current.unreadCount - 1) : current.unreadCount,
                };
            });
            void queryClient.invalidateQueries({ queryKey: queryKeys.notifications.all });
        },
    });

    const markAllReadMutation = useMutation({
        mutationFn: () => notificationApi.markAllRead(),
        onSuccess: () => {
            const now = new Date().toISOString();
            syncNotificationCaches((current) => ({
                ...current,
                notifications: current.notifications.map((item) => ({
                    ...item,
                    isRead: true,
                    readAt: item.readAt || now,
                })),
                unreadCount: 0,
            }));
            void queryClient.invalidateQueries({ queryKey: queryKeys.notifications.all });
        },
    });

    const handleNotificationSelect = async (notification: Notification) => {
        if (!notification.isRead) {
            try {
                await markReadMutation.mutateAsync(notification.id);
            } catch {
                return;
            }
        }

        setOpen(false);

        if (!notification.actionUrl) {
            return;
        }

        const target = resolveNotificationTarget(notification.actionUrl);
        if (target.isExternal) {
            window.location.assign(target.href);
            return;
        }

        void router.push(target.href);
    };

    const handleOpenChange = (nextOpen: boolean) => {
        setOpen(nextOpen);
        if (nextOpen) {
            void onRefresh?.();
        }
    };

    const triggerClassName =
        variant === "mobile"
            ? "h-11 w-11 rounded-full hover:bg-muted relative"
            : "h-11 w-11 rounded-full relative text-muted-foreground hover:text-foreground";
    const iconClassName = variant === "mobile" ? "h-6 w-6 text-foreground/80" : "h-5 w-5";

    return (
        <DropdownMenu open={open} onOpenChange={handleOpenChange}>
            <DropdownMenuTrigger asChild>
                <Button
                    variant="ghost"
                    size="icon"
                    className={triggerClassName}
                    aria-label={unreadCount > 0 ? `${unreadCount} unread notifications` : "Notifications"}
                >
                    <Bell className={iconClassName} />
                    {unreadCount > 0 ? (
                        variant === "mobile" ? (
                            <span className="absolute top-2.5 right-2.5 h-2 w-2 rounded-full border-2 border-background bg-red-500" />
                        ) : (
                            <span className="absolute -top-0.5 -right-0.5 flex h-[18px] min-w-[18px] items-center justify-center rounded-full border-2 border-background bg-red-500 px-1 text-2xs font-bold text-white">
                                {unreadCount > 99 ? "99+" : unreadCount}
                            </span>
                        )
                    ) : null}
                </Button>
            </DropdownMenuTrigger>

            <DropdownMenuContent
                align="end"
                sideOffset={8}
                className="w-[min(90vw,17rem)] rounded-2xl border border-slate-200 bg-white p-0 shadow-lg"
                onCloseAutoFocus={(event) => event.preventDefault()}
            >
                <div className="border-b border-slate-100 px-3 py-2">
                    <div className="flex items-center justify-between gap-2">
                        <p className="text-xs font-semibold text-foreground">Notifications</p>
                        {unreadCount > 0 ? (
                            <Button
                                variant="ghost"
                                size="sm"
                                className="h-7 rounded-full px-2.5 text-[11px] font-medium text-foreground-tertiary hover:bg-slate-100"
                                onClick={() => markAllReadMutation.mutate()}
                                disabled={markAllReadMutation.isPending}
                            >
                                Mark all read
                            </Button>
                        ) : null}
                    </div>
                </div>

                <div className="max-h-[18rem] overflow-y-auto px-1.5 py-1.5">
                    {notifications.length === 0 ? (
                        <div className="flex flex-col items-center justify-center gap-2 rounded-xl border border-dashed border-slate-200 bg-slate-50 px-4 py-6 text-center">
                            <div className="flex h-8 w-8 items-center justify-center rounded-xl bg-white shadow-sm">
                                <Inbox className="h-4 w-4 text-foreground-subtle" />
                            </div>
                            <div className="space-y-0.5">
                                <p className="text-xs font-semibold text-foreground">No notifications</p>
                                <p className="text-[11px] leading-4 text-muted-foreground">Updates will appear here.</p>
                            </div>
                        </div>
                    ) : (
                        <div className="space-y-1">
                            {notifications.map((notification) => (
                                <NotificationItemCard
                                    key={notification.id}
                                    notification={notification}
                                    onSelect={handleNotificationSelect}
                                    isProcessing={markReadMutation.isPending}
                                />
                            ))}
                        </div>
                    )}
                </div>
            </DropdownMenuContent>
        </DropdownMenu>
    );
}

