"use client";

import { useCallback, useEffect, useState } from "react";

export type BrowseViewMode = "grid" | "list";

const BROWSE_VIEW_STORAGE_KEY = "esparex:browse-view";

function isBrowseViewMode(value: string | null): value is BrowseViewMode {
  return value === "grid" || value === "list";
}

export function usePersistedBrowseView(defaultView: BrowseViewMode = "grid") {
  const [view, setViewState] = useState<BrowseViewMode>(defaultView);

  useEffect(() => {
    try {
      const storedValue = window.localStorage.getItem(BROWSE_VIEW_STORAGE_KEY);
      if (isBrowseViewMode(storedValue)) {
        setViewState(storedValue);
      }
    } catch {
      // Storage access can fail in restricted contexts. Ignore and keep defaults.
    }
  }, []);

  const setView = useCallback((nextView: BrowseViewMode) => {
    setViewState(nextView);
    try {
      window.localStorage.setItem(BROWSE_VIEW_STORAGE_KEY, nextView);
    } catch {
      // Ignore storage errors and keep the in-memory state.
    }
  }, []);

  return [view, setView] as const;
}

"use client";

import { useEffect, useState } from "react";
import { useRouter } from "next/navigation";
import { useForm, type FieldErrors, type UseFormReturn, type UseFormSetValue } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import { CheckCircle2 } from "lucide-react";

import { notify } from "@/lib/notify";
import { TOAST_MESSAGES } from "@/config/toastMessages";
import { mapErrorToMessage } from "@/lib/errorMapper";
import { injectApiErrors } from "@/lib/injectApiErrors";
import logger from "@/lib/logger";
import type { User } from "@/types/User";
import type { Path, FieldValues } from "react-hook-form";
import { normalizeBusinessStatus } from "@/lib/status/statusNormalization";
import {
    getMyBusiness,
    registerBusiness,
    updateBusiness,
    uploadBusinessImage,
    type Business as UserBusiness,
    type CreateBusinessDTO,
} from "@/lib/api/user/businesses";

import {
    AlertDialog,
    AlertDialogAction,
    AlertDialogContent,
    AlertDialogDescription,
    AlertDialogFooter,
    AlertDialogTitle,
} from "@/components/ui/alert-dialog";

import { BusinessProfileWizard } from "./BusinessProfileWizard";
import { getBusinessWizardFieldsForStep, useBusinessWizardBridge } from "./useBusinessWizardBridge";
import {
    businessRegistrationSchema,
    type BusinessRegistrationFormData,
    type BusinessRegistrationFormInput,
} from "@/schemas/businessRegistration.schema";
import {
    businessEditSchema,
    type BusinessEditFormData,
    type BusinessEditFormInput,
} from "@/schemas/businessEditPayload.schema";

type BusinessProfileFlowMode = "registration" | "edit";
type BusinessProfileWizardVariant = "registration" | "application-edit" | "live-edit";
type SubmissionStatus = {
    title: string;
    detail: string;
};

interface BusinessProfileFlowProps {
    mode: BusinessProfileFlowMode;
    user: User | null;
    initialBusiness?: UserBusiness | null;
    onRefreshUser?: () => void | Promise<void>;
    onComplete?: () => void;
    onClose?: () => void;
}

type BusinessWizardFormShape = {
    businessName: string;
    businessDescription: string;
    fullAddress: string;
    currentLocationDisplay: string;
    currentLocationSource?: "auto" | "";
    currentLocationCity?: string | null;
    currentLocationState?: string | null;
    currentLocationPincode?: string | null;
    currentLocationCountry?: string | null;
    coordinates?: unknown | null;
    contactNumber: string;
    email: string;
};

const asOptionalString = (value: unknown): string | undefined => {
    if (typeof value !== "string") return undefined;
    const normalized = value.trim();
    return normalized.length > 0 ? normalized : undefined;
};

const joinAddressParts = (...parts: unknown[]): string =>
    parts
        .map((part) => asOptionalString(part))
        .filter((part): part is string => Boolean(part))
        .join(", ");

function buildBusinessPayloadBase(data: BusinessWizardFormShape): Omit<CreateBusinessDTO, "images" | "documents"> {
    return {
        name: data.businessName.trim(),
        description: data.businessDescription.trim(),
        location: {
            address: data.fullAddress.trim(),
            display: data.currentLocationDisplay.trim(),
            ...(asOptionalString(data.currentLocationCity) ? { city: data.currentLocationCity?.trim() } : {}),
            ...(asOptionalString(data.currentLocationState) ? { state: data.currentLocationState?.trim() } : {}),
            ...(asOptionalString(data.currentLocationPincode) ? { pincode: data.currentLocationPincode?.trim() } : {}),
            ...(asOptionalString(data.currentLocationCountry) ? { country: data.currentLocationCountry?.trim() } : {}),
            coordinates: (data.coordinates as CreateBusinessDTO["location"]["coordinates"]) || undefined,
        },
        mobile: data.contactNumber.replace(/\D/g, "").slice(-10),
        email: data.email.trim(),
    };
}

function mapBusinessToEditDefaults(business: UserBusiness): BusinessEditFormInput {
    const fullAddress =
        asOptionalString(business.location.address)
        || joinAddressParts(
            business.location.shopNo,
            business.location.street,
            business.location.landmark,
            business.location.city,
            business.location.state,
            business.location.pincode,
        );
    const currentLocationDisplay =
        asOptionalString(business.location.display)
        || asOptionalString(business.location.formattedAddress)
        || joinAddressParts(business.location.city, business.location.state)
        || fullAddress;

    return {
        businessName: business.name || "",
        businessDescription: business.description || "",
        contactNumber: business.mobile || "",
        email: business.email || "",
        fullAddress: fullAddress || "",
        currentLocationDisplay: currentLocationDisplay || "",
        currentLocationSource: "",
        currentLocationCity: business.location.city || "",
        currentLocationState: business.location.state || "",
        currentLocationPincode: business.location.pincode || "",
        currentLocationCountry: business.location.country || "",
        coordinates: business.location.coordinates || null,
        shopImages: business.images || [],
        idProof: business.documents?.idProof?.[0] || null,
        businessProof: business.documents?.businessProof?.[0] || null,
        certificates: business.documents?.certificates || [],
        idProofType: business.documents?.idProofType,
    };
}

function getBusinessEditVariant(status: UserBusiness["status"] | undefined): BusinessProfileWizardVariant {
    return normalizeBusinessStatus(status, "pending") === "live" ? "live-edit" : "application-edit";
}

function useBusinessProfileWizardController<TFormShape extends FieldValues>(
    form: UseFormReturn<TFormShape, any, any>,
    options: { requireDocuments: boolean },
) {
    const [currentStep, setCurrentStep] = useState(0);
    const [formError, setFormError] = useState<string | null>(null);
    const {
        trigger,
        watch,
        setValue,
        formState: { errors, isSubmitting },
    } = form;

    const formData = watch();
    const { legacyFormData, setLegacyFormData } = useBusinessWizardBridge({
        formData: formData as TFormShape,
        errors: errors as FieldErrors<TFormShape>,
        setValue: setValue as unknown as UseFormSetValue<TFormShape>,
    });

    const handleNext = async () => {
        if (formError) setFormError(null);

        const isValid = await trigger(
            getBusinessWizardFieldsForStep(currentStep, { requireDocuments: options.requireDocuments }) as Path<TFormShape>[],
        );
        if (!isValid) return;

        setCurrentStep((previous) => previous + 1);
    };

    return {
        currentStep,
        setCurrentStep,
        formError,
        setFormError,
        isSubmitting,
        legacyFormData,
        setLegacyFormData,
        handleNext,
    };
}

async function processStagedFiles(
    items: Array<File | string>,
    options?: {
        label?: string;
        onProgress?: (status: SubmissionStatus) => void;
    },
) {
    const results: string[] = [];
    const totalUploadable = items.filter((item): item is File => item instanceof File).length;
    let uploadedCount = 0;

    for (const item of items) {
        if (!(item instanceof File)) {
            results.push(item);
            continue;
        }

        uploadedCount += 1;
        options?.onProgress?.({
            title: options.label || "Uploading files",
            detail: `${uploadedCount} of ${totalUploadable} file${totalUploadable === 1 ? "" : "s"} uploaded`,
        });

        const isDocument = item.type === "application/pdf";
        results.push(await uploadBusinessImage(item, isDocument ? "documents" : "businesses"));
    }
    return results;
}

function BusinessRegistrationFlow({
    user,
    initialBusiness: _initialBusiness,
    onRefreshUser,
    onComplete,
    onClose,
}: Omit<BusinessProfileFlowProps, "mode">) {
    const router = useRouter();
    const normalizedContactNumber = (user?.mobile || "").replace(/\D/g, "").slice(-10);
    const [showSuccessDialog, setShowSuccessDialog] = useState(false);
    const [submissionStatus, setSubmissionStatus] = useState<SubmissionStatus | null>(null);

    const form = useForm<BusinessRegistrationFormInput, undefined, BusinessRegistrationFormData>({
        resolver: zodResolver(businessRegistrationSchema),
        mode: "onBlur",
        reValidateMode: "onChange",
        defaultValues: {
            businessName: "",
            businessDescription: "",
            fullAddress: "",
            currentLocationDisplay: "",
            currentLocationSource: "",
            currentLocationCity: "",
            currentLocationState: "",
            currentLocationPincode: "",
            currentLocationCountry: "",
            coordinates: null,
            contactNumber: normalizedContactNumber,
            email: user?.email || "",
            idProof: null,
            businessProof: null,
            certificates: [],
            shopImages: [],
            idProofType: undefined,
        },
    });

    const wizard = useBusinessProfileWizardController<BusinessRegistrationFormInput>(form, {
        requireDocuments: true,
    });

    const handleClose = () => {
        if (onClose) {
            onClose();
            return;
        }

        void router.push("/");
    };

    const onValidSubmit = async (data: BusinessRegistrationFormData) => {
        wizard.setFormError(null);
        setSubmissionStatus({
            title: "Preparing application",
            detail: "Checking files and details before secure upload.",
        });

        try {
            const images = await processStagedFiles(data.shopImages, {
                label: "Uploading shop photos",
                onProgress: setSubmissionStatus,
            });
            const idProof = data.idProof ? await processStagedFiles([data.idProof], {
                label: "Uploading owner ID proof",
                onProgress: setSubmissionStatus,
            }) : [];
            const businessProof = data.businessProof ? await processStagedFiles([data.businessProof], {
                label: "Uploading business proof",
                onProgress: setSubmissionStatus,
            }) : [];
            const certificates = await processStagedFiles(data.certificates ?? [], {
                label: "Uploading supporting certificates",
                onProgress: setSubmissionStatus,
            });

            const payload: CreateBusinessDTO = {
                ...buildBusinessPayloadBase(data),
                images,
                documents: {
                    idProof,
                    idProofType: data.idProofType,
                    businessProof,
                    certificates,
                },
            };

            setSubmissionStatus({
                title: "Submitting application",
                detail: "Sending your business details and verification documents to the review team.",
            });
            const created = await registerBusiness(payload);
            if (!created) {
                throw new Error("Business registration failed.");
            }

            setSubmissionStatus(null);
            setShowSuccessDialog(true);
        } catch (error: unknown) {
            setSubmissionStatus(null);
            wizard.setFormError(mapErrorToMessage(error, "Failed to submit business registration."));
        }
    };

    const handleSuccessAcknowledge = async () => {
        setShowSuccessDialog(false);
        await onRefreshUser?.();
        window.dispatchEvent(new CustomEvent("esparex_auth_update"));

        if (onComplete) {
            onComplete();
            return;
        }

        void router.push("/account/business");
    };

    return (
        <BusinessProfileWizard
            wizardVariant="registration"
            title="Register Business"
            user={user}
            currentStep={wizard.currentStep}
            formData={wizard.legacyFormData}
            setFormData={wizard.setLegacyFormData}
            formError={wizard.formError}
            submissionStatus={submissionStatus}
            isSubmitting={wizard.isSubmitting}
            submitLabel="Submit Application"
            onNext={wizard.handleNext}
            onHeaderBack={handleClose}
            onStepChange={wizard.setCurrentStep}
            onSubmit={form.handleSubmit(onValidSubmit)}
        >
            <AlertDialog open={showSuccessDialog} onOpenChange={setShowSuccessDialog}>
                <AlertDialogContent className="max-w-md rounded-2xl border-0 p-8 shadow-2xl">
                    <div className="flex flex-col items-center space-y-6 text-center">
                        <div className="flex h-20 w-20 items-center justify-center rounded-full border-4 border-emerald-100 bg-emerald-50 shadow-inner animate-in zoom-in duration-500">
                            <CheckCircle2 className="h-10 w-10 text-emerald-500" />
                        </div>
                        <div className="space-y-2">
                            <AlertDialogTitle className="text-2xl font-bold tracking-tight text-foreground">
                                Application Submitted!
                            </AlertDialogTitle>
                            <AlertDialogDescription className="leading-relaxed text-muted-foreground">
                                Your business verification request has been received. Our team will review your documents and verify your account within 24-48 hours.
                            </AlertDialogDescription>
                        </div>
                        <div className="h-1 w-full overflow-hidden rounded-full bg-slate-50">
                            <div className="h-full w-1/3 animate-[progress_2s_ease-in-out_infinite] bg-emerald-500" />
                        </div>
                        <AlertDialogFooter className="w-full gap-3 sm:flex-col">
                            <AlertDialogAction
                                onClick={() => void handleSuccessAcknowledge()}
                                className="h-12 w-full rounded-xl bg-slate-900 font-bold text-white shadow-lg shadow-slate-200 transition-all hover:bg-slate-800"
                            >
                                Got it, thanks!
                            </AlertDialogAction>
                        </AlertDialogFooter>
                    </div>
                </AlertDialogContent>
            </AlertDialog>
        </BusinessProfileWizard>
    );
}

function BusinessEditProfileFlow({
    user,
    initialBusiness,
    onRefreshUser,
    onComplete,
    onClose,
}: Omit<BusinessProfileFlowProps, "mode">) {
    const router = useRouter();
    const [isLoading, setIsLoading] = useState(() => !initialBusiness);
    const [businessId, setBusinessId] = useState<string | null>(initialBusiness?.id ?? null);
    const [loadedBusiness, setLoadedBusiness] = useState<UserBusiness | null>(initialBusiness ?? null);
    const [submissionStatus, setSubmissionStatus] = useState<SubmissionStatus | null>(null);
    const initialEditDefaults: BusinessEditFormInput = initialBusiness
        ? mapBusinessToEditDefaults(initialBusiness)
        : {
            businessName: "",
            businessDescription: "",
            fullAddress: "",
            currentLocationDisplay: "",
            currentLocationSource: "",
            currentLocationCity: "",
            currentLocationState: "",
            currentLocationPincode: "",
            currentLocationCountry: "",
            coordinates: null,
            contactNumber: "",
            email: "",
            idProofType: undefined,
            idProof: null,
            businessProof: null,
            certificates: [],
            shopImages: [],
        };

    const form = useForm<BusinessEditFormInput, undefined, BusinessEditFormData>({
        resolver: zodResolver(businessEditSchema),
        mode: "onBlur",
        reValidateMode: "onChange",
        defaultValues: initialEditDefaults,
    });

    const wizard = useBusinessProfileWizardController<BusinessEditFormInput>(form, {
        requireDocuments: false,
    });
    const { setFormError } = wizard;
    const wizardVariant = getBusinessEditVariant(loadedBusiness?.status);
    const normalizedBusinessStatus = normalizeBusinessStatus(loadedBusiness?.status, "pending");
    const editTitle =
        wizardVariant === "live-edit"
            ? "Edit Business Profile"
            : normalizedBusinessStatus === "rejected"
                ? "Review & Resubmit Application"
                : "Update Business Application";
    const submitLabel =
        wizardVariant === "live-edit"
            ? "Save Changes"
            : normalizedBusinessStatus === "rejected"
                ? "Save & Resubmit"
                : "Update Application";

    useEffect(() => {
        const hydrateBusiness = (business: UserBusiness) => {
            setLoadedBusiness(business);
            setBusinessId(business.id);
            form.reset(mapBusinessToEditDefaults(business));
            setIsLoading(false);
        };

        async function loadBusiness() {
            try {
                if (initialBusiness) {
                    setIsLoading(false);
                    return;
                }

                if (loadedBusiness && businessId) {
                    setIsLoading(false);
                    return;
                }

                const business = await getMyBusiness({ silent: true });
                if (!business) {
                    setFormError("No business profile found.");
                    void router.push("/account/business/apply");
                    return;
                }

                hydrateBusiness(business);
            } catch (error) {
                logger.error("Failed to load business details", error);
                setFormError(TOAST_MESSAGES.LOAD_FAILED);
            } finally {
                setIsLoading(false);
            }
        }

        void loadBusiness();
    }, [businessId, form, initialBusiness, loadedBusiness, router, setFormError]);

    const onValidSubmit = async (data: BusinessEditFormData) => {
        if (!businessId) return;

        wizard.setFormError(null);
        setSubmissionStatus({
            title: "Preparing changes",
            detail: "Checking updated files and business details before upload.",
        });

        try {
            const images = await processStagedFiles((data.shopImages ?? []) as Array<File | string>, {
                label: "Uploading shop photos",
                onProgress: setSubmissionStatus,
            });
            const idProof = data.idProof ? await processStagedFiles([data.idProof as File | string], {
                label: "Uploading owner ID proof",
                onProgress: setSubmissionStatus,
            }) : [];
            const businessProof = data.businessProof ? await processStagedFiles([data.businessProof as File | string], {
                label: "Uploading business proof",
                onProgress: setSubmissionStatus,
            }) : [];
            const certificates = await processStagedFiles((data.certificates ?? []) as Array<File | string>, {
                label: "Uploading supporting certificates",
                onProgress: setSubmissionStatus,
            });

            const payload: Partial<CreateBusinessDTO> = {
                ...buildBusinessPayloadBase(data),
                images,
                documents: {
                    idProof,
                    idProofType: data.idProofType,
                    businessProof,
                    certificates,
                },
            };

            setSubmissionStatus({
                title: "Saving business profile",
                detail: "Applying your latest business details and review documents.",
            });
            const updated = await updateBusiness(businessId, payload);
            if (!updated) {
                throw new Error("Update failed");
            }

            setLoadedBusiness(updated);
            setSubmissionStatus(null);

            if (normalizeBusinessStatus(updated.status, "pending") === "pending") {
                notify.success(
                    wizardVariant === "live-edit"
                        ? "Changes saved. Sensitive updates sent your business back for admin review."
                        : "Application updated. It remains under admin review.",
                );
            } else {
                notify.success(TOAST_MESSAGES.UPDATE_SUCCESS);
            }

            await onRefreshUser?.();
            window.dispatchEvent(new CustomEvent("esparex_auth_update"));

            if (onComplete) {
                onComplete();
                return;
            }

            void router.push("/account/business");
        } catch (error: unknown) {
            setSubmissionStatus(null);
            logger.error(error);
            const injected = injectApiErrors(form, error);
            if (!injected) {
                wizard.setFormError(mapErrorToMessage(error, TOAST_MESSAGES.LOAD_FAILED));
            }
        }
    };

    if (isLoading) {
        return (
            <div className="flex items-center justify-center py-20">
                <div className="h-12 w-12 animate-spin rounded-full border-b-2 border-primary" />
            </div>
        );
    }

    return (
        <BusinessProfileWizard
            wizardVariant={wizardVariant}
            title={editTitle}
            user={user}
            currentStep={wizard.currentStep}
            formData={wizard.legacyFormData}
            setFormData={wizard.setLegacyFormData}
            formError={wizard.formError}
            submissionStatus={submissionStatus}
            isSubmitting={wizard.isSubmitting}
            submitLabel={submitLabel}
            onNext={wizard.handleNext}
            onHeaderBack={() => {
                if (onClose) {
                    onClose();
                    return;
                }
                void router.push("/account/business");
            }}
            onStepChange={wizard.setCurrentStep}
            onSubmit={form.handleSubmit(onValidSubmit)}
        />
    );
}

export function BusinessProfileFlow(props: BusinessProfileFlowProps) {
    if (props.mode === "registration") {
        return <BusinessRegistrationFlow {...props} />;
    }

    return <BusinessEditProfileFlow {...props} />;
}

import { type ReactNode, useEffect, useMemo, useRef, useState } from "react";
import { Loader2, Target } from "lucide-react";

import { Button } from "@/components/ui/button";
import { Field } from "@/components/ui/field";
import { FormError } from "@/components/ui/FormError";
import { Input } from "@/components/ui/input";
import { Textarea } from "@/components/ui/textarea";
import logger from "@/lib/logger";
import {
    getCurrentLocationResult,
    normalizeLocationName,
    reverseGeocode,
} from "@/lib/location/locationService";
import { normalizeCoordinates } from "@/lib/location/coordinates";
import type { AppLocation } from "@/types/location";

import type { StepBaseProps } from "./types";

interface StepAddressProps extends StepBaseProps {}

const asOptionalString = (value: unknown): string => {
    if (typeof value !== "string") return "";
    return value.trim();
};

const buildDetectedLocationDisplay = (location: AppLocation): string =>
    normalizeLocationName(
        location.display
        || location.formattedAddress
        || [location.city, location.state].filter(Boolean).join(", ")
        || "Current location",
    );

const getCurrentLocationSourceLabel = (source: "auto" | ""): string => {
    if (source === "auto") return "GPS";
    return "";
};

const isGenericCapturedLocation = (display: string): boolean =>
    ["current location", "current location captured", "approximate current location"].includes(display.toLowerCase());

export const applyDetectedCurrentLocation = ({
    detectedLocation,
    setFormData,
}: {
    detectedLocation: AppLocation;
    setFormData: StepAddressProps["setFormData"];
}) => {
    const normalizedCoordinates = normalizeCoordinates(detectedLocation.coordinates);
    const display = buildDetectedLocationDisplay(detectedLocation);

    setFormData((previous) => ({
        ...previous,
        currentLocationDisplay: display,
        currentLocationSource: "auto",
        currentLocationCity: detectedLocation.city || previous.currentLocationCity,
        currentLocationState: detectedLocation.state || previous.currentLocationState,
        currentLocationPincode: detectedLocation.pincode || previous.currentLocationPincode,
        currentLocationCountry: detectedLocation.country || previous.currentLocationCountry,
        coordinates: normalizedCoordinates || null,
        isSnapped: detectedLocation.isSnapped,
    }));
};

function CompactReadonlyField({
    id,
    label,
    value,
    placeholder,
    helperText,
    error,
    badge,
    fieldAction,
    children,
}: {
    id: string;
    label: string;
    value: string;
    placeholder?: string;
    helperText?: string;
    error?: string;
    badge?: ReactNode;
    fieldAction?: ReactNode;
    children?: ReactNode;
}) {
    return (
        <div className="space-y-1.5">
            <div className="flex flex-wrap items-center gap-2">
                <label className="text-sm font-medium leading-snug text-foreground-secondary" htmlFor={id}>
                    {label}
                </label>
                {badge}
            </div>
            {helperText ? <p className="text-xs leading-5 text-muted-foreground">{helperText}</p> : null}
            <div className="flex flex-col gap-2 sm:flex-row sm:items-center">
                <Input
                    id={id}
                    value={value}
                    readOnly
                    placeholder={placeholder}
                    className="bg-slate-50 font-medium sm:flex-1"
                    aria-invalid={Boolean(error)}
                />
                {fieldAction ? <div className="sm:shrink-0">{fieldAction}</div> : null}
            </div>
            {children}
            <FormError message={error} className="text-xs font-medium text-destructive" />
        </div>
    );
}

export function StepAddress({
    formData,
    setFormData,
}: StepAddressProps) {
    const [isDetectingLocation, setIsDetectingLocation] = useState(false);
    const [detectFeedback, setDetectFeedback] = useState<string | null>(null);
    const refreshedGenericLocationKeyRef = useRef<string | null>(null);

    const hasCurrentLocation = useMemo(
        () => Boolean(asOptionalString(formData.currentLocationDisplay) && formData.coordinates),
        [formData.coordinates, formData.currentLocationDisplay],
    );
    const currentLocationError = formData.errors?.currentLocationDisplay || formData.errors?.coordinates;
    const sourceLabel = getCurrentLocationSourceLabel(formData.currentLocationSource);
    const normalizedDetectedDisplay = asOptionalString(formData.currentLocationDisplay);
    const normalizedDetectedCoordinates = useMemo(
        () => normalizeCoordinates(formData.coordinates),
        [formData.coordinates],
    );
    const detectedLocationSignature = normalizedDetectedCoordinates
        ? `${normalizedDetectedCoordinates.coordinates[0]}:${normalizedDetectedCoordinates.coordinates[1]}`
        : "";

    useEffect(() => {
        if (
            !normalizedDetectedCoordinates
            || !normalizedDetectedDisplay
            || !isGenericCapturedLocation(normalizedDetectedDisplay)
        ) {
            refreshedGenericLocationKeyRef.current = undefined;
            return;
        }

        if (refreshedGenericLocationKeyRef.current === detectedLocationSignature) {
            return;
        }

        refreshedGenericLocationKeyRef.current = detectedLocationSignature;
        let cancelled = false;

        void (async () => {
            try {
                const refreshedLocation = await reverseGeocode(
                    normalizedDetectedCoordinates.coordinates[1],
                    normalizedDetectedCoordinates.coordinates[0],
                );
                if (!refreshedLocation || cancelled) {
                    return;
                }

                const refreshedDisplay = buildDetectedLocationDisplay(refreshedLocation);
                if (!refreshedDisplay || isGenericCapturedLocation(refreshedDisplay)) {
                    return;
                }

                applyDetectedCurrentLocation({
                    detectedLocation: {
                        ...refreshedLocation,
                        source: "auto",
                    },
                    setFormData,
                });
            } catch (error) {
                logger.warn("Failed to refresh generic detected location label", error);
            }
        })();

        return () => {
            cancelled = true;
        };
    }, [
        detectedLocationSignature,
        formData.currentLocationSource,
        normalizedDetectedCoordinates,
        normalizedDetectedDisplay,
        setFormData,
    ]);

    // B4: Clear GPS feedback on unmount to prevent stale error on re-mount
    useEffect(() => {
        return () => {
            setDetectFeedback(null);
        };
    }, []);

    const handleDetectCurrentLocation = async () => {
        setIsDetectingLocation(true);
        setDetectFeedback(null);
        refreshedGenericLocationKeyRef.current = undefined;

        try {
            const detectionResult = await getCurrentLocationResult({
                allowApproximateFallback: false,
                enableHighAccuracy: true,
                maximumAgeMs: 0,
            });

            if (!detectionResult.location) {
                // B4: Map known GPS failure reasons to user-friendly messages
                const failureReason = detectionResult.failure?.reason;
                let feedbackMsg: string;
                if (failureReason === "permission_denied") {
                    feedbackMsg = "Location permission was denied. Please allow location access in your browser or device settings and try again.";
                } else if (failureReason === "position_unavailable") {
                    feedbackMsg = "Your location could not be determined. Make sure GPS is enabled on your device.";
                } else if (failureReason === "timeout") {
                    feedbackMsg = "Location detection timed out. You may be in a low-signal area — try moving to an open space and retry.";
                } else if (failureReason === "insecure_context" || failureReason === "unsupported") {
                    feedbackMsg = "Location is not supported in this browser or connection. Try using Chrome or Safari over HTTPS.";
                } else {
                    feedbackMsg = detectionResult.failure?.message || "Use current location to continue.";
                }
                setDetectFeedback(feedbackMsg);
                return;
            }

            const normalizedCoordinates = normalizeCoordinates(detectionResult.location.coordinates);
            if (!normalizedCoordinates) {
                setDetectFeedback("We found your location, but could not save the coordinates. Try again.");
                return;
            }

            applyDetectedCurrentLocation({
                detectedLocation: detectionResult.location,
                setFormData,
            });
        } catch (error) {
            logger.error("Current location detection failed", error);
            setDetectFeedback("We couldn't detect your current location right now. Please try again.");
        } finally {
            setIsDetectingLocation(false);
        }
    };

    return (
        <div className="space-y-6">
            <div className="grid gap-3 md:grid-cols-2">
                <CompactReadonlyField
                    id="reg-contact-number"
                    label="Business contact"
                    value={formData.contactNumber}
                    helperText="Uses your verified account mobile number."
                    error={formData.errors?.contactNumber}
                    badge={(
                        <span className="rounded-full bg-emerald-50 px-2.5 py-1 text-xs font-semibold uppercase tracking-wide text-emerald-700">
                            Verified
                        </span>
                    )}
                />

                <CompactReadonlyField
                    id="reg-detected-location"
                    label="Detected location"
                    value={asOptionalString(formData.currentLocationDisplay)}
                    placeholder="No location detected yet"
                    helperText={
                        hasCurrentLocation
                            ? formData.isSnapped
                                ? "Approximate city center recorded. You must provide your precise street address below."
                                : isGenericCapturedLocation(normalizedDetectedDisplay)
                                    ? "Current coordinates recorded. Our location database could not name this spot yet, but you can continue with the full address."
                                    : "GPS location recorded. This proof is required for business registration."
                            : "Required. Tap the location button to record your current GPS position."
                    }
                    error={currentLocationError}
                    badge={(
                        <>
                            <span className="rounded-full bg-slate-100 px-2.5 py-1 text-xs font-semibold uppercase tracking-wide text-foreground-secondary">
                                Required
                            </span>
                            {formData.isSnapped ? (
                                <span className="rounded-full bg-amber-50 px-2.5 py-1 text-xs font-semibold uppercase tracking-wide text-amber-700">
                                    Approximate
                                </span>
                            ) : null}
                            {sourceLabel ? (
                                <span className="rounded-full bg-blue-50 px-2.5 py-1 text-xs font-semibold uppercase tracking-wide text-link-dark">
                                    {sourceLabel}
                                </span>
                            ) : null}
                        </>
                    )}
                    fieldAction={(
                        <Button
                            type="button"
                            variant="outline"
                            onClick={handleDetectCurrentLocation}
                            disabled={isDetectingLocation}
                            size="icon"
                            aria-label={isDetectingLocation ? "Detecting current location" : "Use current location"}
                            title={isDetectingLocation ? "Detecting current location" : "Use current location"}
                            className="h-9 w-9 rounded-xl border-slate-300 bg-white text-foreground hover:bg-slate-100"
                        >
                            {isDetectingLocation ? (
                                <Loader2 className="h-4 w-4 animate-spin" />
                            ) : (
                                <Target className="h-4 w-4" />
                            )}
                        </Button>
                    )}
                >
                    {detectFeedback ? (
                        <p className="text-xs font-medium text-red-600">{detectFeedback}</p>
                    ) : null}
                </CompactReadonlyField>

                {asOptionalString(formData.currentLocationPincode) ? (
                  <CompactReadonlyField
                      id="reg-detected-pincode"
                      label="Detected pincode"
                      value={asOptionalString(formData.currentLocationPincode)}
                      placeholder="—"
                      helperText="Auto-resolved from your GPS position."
                      error={formData.errors?.currentLocationPincode}
                      badge={(
                          <span className="rounded-full bg-blue-50 px-2.5 py-1 text-xs font-semibold uppercase tracking-wide text-link-dark">
                              Auto-filled
                          </span>
                      )}
                  />
                ) : null}
            </div>

            {hasCurrentLocation ? (
                <Field
                    label="Full address"
                    required
                    error={formData.errors?.fullAddress}
                    className="space-y-1.5"
                >
                    <div className="flex items-center justify-between">
                        <span className="text-xs leading-5 text-muted-foreground">
                            Include shop/building name, street/area, pincode, and landmark.
                        </span>
                        <span className={`shrink-0 ml-3 text-xs font-medium ${formData.fullAddress.length >= 300 ? "text-amber-600" : "text-muted-foreground"}`}>
                            {formData.fullAddress.length}/300
                        </span>
                    </div>
                    <Textarea
                        id="reg-full-address"
                        value={formData.fullAddress}
                        onChange={(event) =>
                            setFormData({
                                ...formData,
                                fullAddress: event.target.value.slice(0, 300),
                            })
                        }
                        placeholder="e.g. Shop 4, MG Road, Near Old Bus Stand, Guntur, Andhra Pradesh 522413"
                        maxLength={300}
                        rows={4}
                        aria-invalid={Boolean(formData.errors?.fullAddress)}
                    />
                </Field>
            ) : null}
        </div>
    );
}

