import { useState, useEffect } from 'react';
import type { AppRouterInstance } from 'next/dist/shared/lib/app-router-context.shared-runtime';
import { getListingPhone, type Listing as Ad } from '@/lib/api/user/listings';
import type { User } from '@/types/User';
import { notify } from '@/lib/notify';
import { buildLoginUrl } from '@/lib/authHelpers';

export function usePhoneReveal(ad: Ad | undefined | null, user: User | undefined | null, router: AppRouterInstance) {
  const [revealedPhone, setRevealedPhone] = useState<string | null>(null);
  const [isPhoneMasked, setIsPhoneMasked] = useState(false);
  const [phoneMessage, setPhoneMessage] = useState<string | null>(null);
  const [isPhoneLoading, setIsPhoneLoading] = useState(false);

  useEffect(() => {
    setRevealedPhone(null);
    setIsPhoneMasked(false);
    setPhoneMessage(null);
  }, [ad?.id]);

  const handleRevealPhone = async () => {
    if (!ad?.id || isPhoneLoading) return;

    if (revealedPhone && !isPhoneMasked) {
      window.location.href = `tel:${revealedPhone}`;
      return;
    }

    if (revealedPhone && isPhoneMasked && !user) {
      const returnTo = `${window.location.pathname}${window.location.search}${window.location.hash}`;
      void router.push(buildLoginUrl(returnTo));
      return;
    }

    setIsPhoneLoading(true);
    setPhoneMessage(null);

    try {
      const result = await getListingPhone(ad.id);
      if (result?.mobile) {
        const resolvedContactNumber = result.mobile;
        setRevealedPhone(resolvedContactNumber);
        setIsPhoneMasked(false);
        setPhoneMessage(null);
        return;
      }

      if (result?.masked) {
        setRevealedPhone(result.masked);
        setIsPhoneMasked(true);
        setPhoneMessage("Login to reveal the full phone number.");
        return;
      }

      setPhoneMessage("Phone number is unavailable for this listing.");
    } catch (revealError) {
      const backendCode = String(
        (revealError as { context?: { backendErrorCode?: unknown } })?.context?.backendErrorCode || ""
      );
      if (backendCode === "PHONE_REQUEST_REQUIRED") {
        const message = "Seller shares phone numbers on request only. Use chat first.";
        setPhoneMessage(message);
        notify.info(message);
      } else if (backendCode === "PHONE_HIDDEN") {
        const message = "Seller chose not to share a phone number for this listing.";
        setPhoneMessage(message);
        notify.info(message);
      } else {
        notify.error(revealError instanceof Error ? revealError.message : "Failed to reveal phone number");
      }
    } finally {
      setIsPhoneLoading(false);
    }
  };

  return { revealedPhone, isPhoneMasked, phoneMessage, isPhoneLoading, handleRevealPhone };
}

"use client";

import { useState, useRef } from "react";
import Image from "next/image";
import { Card, CardContent } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Share2, Heart, ChevronLeft, ChevronRight } from "lucide-react";
import { DEFAULT_IMAGE_PLACEHOLDER, toSafeImageArray } from "@/lib/image/imageUrl";
import { MARKETPLACE_CARD_FILL_SIZES } from "@/lib/imageSizes";

interface AdImageCarouselProps {
    images: string[];
    title: string;
    isFavorited: boolean;
    onFavorite: () => void;
    onShare: () => void;
    showActionButtons?: boolean;
}

const SWIPE_THRESHOLD = 50; // px

export function AdImageCarousel({ images, title, isFavorited, onFavorite, onShare, showActionButtons = true }: AdImageCarouselProps) {
    const [currentImageIndex, setCurrentImageIndex] = useState(0);
    const [isLightboxOpen, setIsLightboxOpen] = useState(false);
    const touchStartX = useRef<number | null>(null);

    const nextImage = () => {
        setCurrentImageIndex((prev: number) => (prev + 1) % safeImages.length);
    };

    const prevImage = () => {
        setCurrentImageIndex((prev: number) => (prev - 1 + safeImages.length) % safeImages.length);
    };

    const handleTouchStart = (e: React.TouchEvent) => {
        touchStartX.current = e.touches[0]?.clientX ?? null;
    };

    const handleTouchEnd = (e: React.TouchEvent) => {
        if (touchStartX.current === undefined) return;
        const diff = touchStartX.current - (e.changedTouches[0]?.clientX ?? 0);
        if (Math.abs(diff) >= SWIPE_THRESHOLD) {
            diff > 0 ? nextImage() : prevImage();
        }
        touchStartX.current = undefined;
    };

    const normalizedImages = toSafeImageArray(images);
    const safeImages = normalizedImages.length > 0 ? normalizedImages : [DEFAULT_IMAGE_PLACEHOLDER];

    return (
        <>
        <Card className="rounded-none md:rounded-[2.5rem] overflow-hidden border-none shadow-none md:shadow-[0_8px_30px_rgb(0,0,0,0.04)] bg-white md:p-2">
            <CardContent className="p-0">
                <div
                    className="relative aspect-[4/3] md:aspect-[16/10] bg-slate-100 rounded-none md:rounded-[2rem] overflow-hidden group/main cursor-pointer"
                    onTouchStart={handleTouchStart}
                    onTouchEnd={handleTouchEnd}
                    onClick={() => setIsLightboxOpen(true)}
                    role="button"
                    aria-label="View full-size image"
                    tabIndex={0}
                    onKeyDown={(e) => { if (e.key === "Enter" || e.key === " ") setIsLightboxOpen(true); }}
                >
                    <Image
                        src={safeImages[currentImageIndex]!}
                        alt={title}
                        fill
                        sizes={MARKETPLACE_CARD_FILL_SIZES}
                        priority
                        unoptimized
                        className="w-full h-full object-cover transition-transform duration-700 group-hover/main:scale-105"
                    />

                    {/* Share and Favorite Buttons */}
                    {showActionButtons && (
                        <div className="absolute top-3 right-3 md:top-4 md:right-4 flex gap-2" onClick={(e) => e.stopPropagation()}>
                            <Button
                                size="icon"
                                variant="secondary"
                                className="h-11 w-11 rounded-full bg-white/90 backdrop-blur-md hover:bg-white shadow-lg border-none transition-all active:scale-90"
                                onClick={onShare}
                                aria-label="Share this ad"
                            >
                                <Share2 className="h-4 w-4 text-foreground-tertiary" />
                            </Button>
                            <Button
                                size="icon"
                                variant="secondary"
                                className="h-11 w-11 rounded-full bg-white/90 backdrop-blur-md hover:bg-white shadow-lg border-none transition-all active:scale-90"
                                onClick={onFavorite}
                                aria-label="Add to favorites"
                            >
                                <Heart
                                    className={`h-4 w-4 ${isFavorited ? "fill-red-500 text-red-500" : "text-foreground-tertiary"}`}
                                />
                            </Button>
                        </div>
                    )}

                    {/* Image counter pill */}
                    {safeImages.length > 1 && (
                        <div className="absolute bottom-3 left-1/2 -translate-x-1/2 bg-black/40 backdrop-blur-sm text-white text-xs font-semibold px-3 py-1 rounded-full">
                            {currentImageIndex + 1} / {safeImages.length}
                        </div>
                    )}

                    {/* Navigation Arrows */}
                    {safeImages.length > 1 && (
                        <>
                            <Button
                                size="icon"
                                variant="secondary"
                                className="absolute left-3 md:left-4 top-1/2 -translate-y-1/2 h-11 w-11 rounded-full bg-white/90 backdrop-blur-md hover:bg-white shadow-lg border-none md:opacity-0 md:group-hover/main:opacity-100 transition-all active:scale-90"
                                onClick={(e) => { e.stopPropagation(); prevImage(); }}
                                aria-label="Previous image"
                            >
                                <ChevronLeft className="h-5 w-5 md:h-6 md:w-6 text-foreground-tertiary" />
                            </Button>
                            <Button
                                size="icon"
                                variant="secondary"
                                className="absolute right-3 md:right-4 top-1/2 -translate-y-1/2 h-11 w-11 rounded-full bg-white/90 backdrop-blur-md hover:bg-white shadow-lg border-none md:opacity-0 md:group-hover/main:opacity-100 transition-all active:scale-90"
                                onClick={(e) => { e.stopPropagation(); nextImage(); }}
                                aria-label="Next image"
                            >
                                <ChevronRight className="h-5 w-5 md:h-6 md:w-6 text-foreground-tertiary" />
                            </Button>
                        </>
                    )}
                </div>

                {/* Thumbnail Carousel */}
                {safeImages.length > 1 && (
                    <div className="px-3 py-3 md:px-4 md:py-4 bg-transparent">
                        <div className="flex gap-2 md:gap-3 overflow-x-auto pb-1 scrollbar-hide">
                            {safeImages.map((image: string, index: number) => (
                                <button
                                    key={index}
                                    onClick={() => setCurrentImageIndex(index)}
                                    className={`flex-shrink-0 w-16 h-16 md:w-20 md:h-20 rounded-xl md:rounded-2xl overflow-hidden border-2 transition-all duration-200 relative ${
                                        index === currentImageIndex
                                            ? "border-green-500 ring-2 ring-green-100 scale-95"
                                            : "border-transparent hover:border-slate-300 opacity-50 hover:opacity-100"
                                    }`}
                                >
                                    <Image
                                        src={image}
                                        alt={`Thumbnail ${index + 1}`}
                                        fill
                                        sizes={MARKETPLACE_CARD_FILL_SIZES}
                                        unoptimized
                                        className="object-cover"
                                    />
                                    {index === currentImageIndex && (
                                        <div className="absolute inset-0 bg-green-500/5" />
                                    )}
                                </button>
                            ))}
                        </div>
                    </div>
                )}
            </CardContent>
        </Card>

        {/* Lightbox / Fullscreen overlay */}
        {isLightboxOpen && (
            <div
                className="fixed inset-0 z-50 flex items-center justify-center bg-black/90 backdrop-blur-sm"
                onClick={() => setIsLightboxOpen(false)}
                onTouchStart={handleTouchStart}
                onTouchEnd={handleTouchEnd}
                role="dialog"
                aria-modal="true"
                aria-label="Image viewer"
            >
                {/* Close button */}
                <button
                    className="absolute top-4 right-4 h-11 w-11 rounded-full bg-white/10 hover:bg-white/20 flex items-center justify-center text-white transition-colors"
                    onClick={() => setIsLightboxOpen(false)}
                    aria-label="Close image viewer"
                >
                    <svg className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
                        <path strokeLinecap="round" strokeLinejoin="round" d="M6 18L18 6M6 6l12 12" />
                    </svg>
                </button>

                {/* Counter */}
                {safeImages.length > 1 && (
                    <div className="absolute top-4 left-1/2 -translate-x-1/2 bg-black/50 text-white text-sm font-semibold px-3 py-1 rounded-full">
                        {currentImageIndex + 1} / {safeImages.length}
                    </div>
                )}

                {/* Main image */}
                <div
                    className="relative w-full max-w-4xl max-h-[90vh] mx-4"
                    onClick={(e) => e.stopPropagation()}
                >
                    <img
                        src={safeImages[currentImageIndex]!}
                        alt={title}
                        className="w-full h-full object-contain max-h-[85vh] rounded-2xl"
                    />
                </div>

                {/* Nav arrows */}
                {safeImages.length > 1 && (
                    <>
                        <button
                            className="absolute left-3 top-1/2 -translate-y-1/2 h-11 w-11 rounded-full bg-white/10 hover:bg-white/20 flex items-center justify-center text-white transition-colors"
                            onClick={(e) => { e.stopPropagation(); prevImage(); }}
                            aria-label="Previous image"
                        >
                            <ChevronLeft className="h-6 w-6" />
                        </button>
                        <button
                            className="absolute right-3 top-1/2 -translate-y-1/2 h-11 w-11 rounded-full bg-white/10 hover:bg-white/20 flex items-center justify-center text-white transition-colors"
                            onClick={(e) => { e.stopPropagation(); nextImage(); }}
                            aria-label="Next image"
                        >
                            <ChevronRight className="h-6 w-6" />
                        </button>
                    </>
                )}
            </div>
        )}
    </>
    );
}

import { useState, useCallback } from "react";
import { UseFormReturn } from "react-hook-form";
import { AdPayload as PostAdFormData } from "@/schemas/adPayload.schema";
import { ListingImage } from "@/types/listing";
import logger from "@/lib/logger";
import { notify } from "@/lib/notify";
import { apiClient } from "@/lib/api/client";

export function useImageUploadWorkflow<T>(
    form: UseFormReturn<PostAdFormData>,
    listingImages: ListingImage[],
    setListingImages: (images: ListingImage[]) => void,
    normalizeIdentityFieldsBeforeSubmit: () => void,
    onValidSubmit: (data: PostAdFormData) => Promise<T>,
    setFormError: (err: string | null) => void,
    setSubmittedAd: (ad: T) => void
) {
    const [isInternalUploading, setIsInternalUploading] = useState(false);

    const submitAd = useCallback(
        async () => {
            normalizeIdentityFieldsBeforeSubmit();
            return form.handleSubmit(async (data: PostAdFormData) => {
                setIsInternalUploading(true);
                try {
                    const updatedImages = [...listingImages];
                    const uploadPromises = updatedImages.map(async (img, idx) => {
                        if (img.isRemote || !img.file) return;

                        const formData = new FormData();
                        formData.append("image", img.file);
                        formData.append("folder", "ads");

                        try {
                            const csrfToken = await (apiClient as unknown as { getCsrfToken?: () => Promise<string> }).getCsrfToken?.() || "";
                            console.log("[FRONTEND CSRF TOKEN]", csrfToken);

                            const headers = {
                                "x-csrf-token": csrfToken,
                            };
                            console.log("[UPLOAD HEADERS]", headers);

                            const response = await fetch("/api/upload/ad-image", {
                                method: "POST",
                                headers,
                                body: formData,
                                credentials: "include",
                            });
                            const payload = await response.json().catch(() => ({} as { success?: boolean; url?: string; error?: string }));
                            const remoteUrl = typeof payload?.url === "string" ? payload.url : "";

                            if (!response.ok || !remoteUrl) {
                                throw new Error(payload?.error || "Image upload failed. Please try again.");
                            }

                            if (payload.success) {
                                updatedImages[idx] = {
                                    ...img,
                                    preview: remoteUrl,
                                    isRemote: true
                                };
                            }
                        } catch (uploadErr) {
                            logger.error("[PostAdSubmit] Image upload failed:", uploadErr);
                            throw new Error(`Failed to upload image ${idx + 1}. Please try again.`);
                        }
                    });

                    await Promise.all(uploadPromises);
                    setListingImages(updatedImages);

                    const ad = await onValidSubmit(data);
                    if (ad) {
                        setSubmittedAd(ad);
                    }
                } catch (err: unknown) {
                    const message = err instanceof Error ? err.message : "Submission failed. Please try again.";
                    logger.error("[PostAdSubmit] Overall submission failed:", err);
                    setFormError(message);
                    notify.error(message);
                } finally {
                    setIsInternalUploading(false);
                }
            }, (errors: unknown) => {
                logger.error("[PostAdSubmit] Form validation errors:", errors);
                const firstErrorKey = Object.keys(errors)[0];
                if (typeof document !== "undefined" && firstErrorKey) {
                    if (firstErrorKey === "images") {
                        document.querySelector("input[type='file']")?.scrollIntoView({ behavior: "smooth", block: "center" });
                    } else {
                        document.querySelector(`[name='${firstErrorKey}']`)?.scrollIntoView({ behavior: "smooth", block: "center" });
                    }
                }
            })();
        },
        [form, listingImages, normalizeIdentityFieldsBeforeSubmit, onValidSubmit, setFormError, setSubmittedAd, setListingImages]
    );

    return { submitAd, isInternalUploading };
}

