import { useUserListingManagement, ListingStatus } from "@/hooks/useUserListingManagement";
import { 
    getMyListings, 
    deleteListing, 
    markListingAsSold, 
    deactivateListing, 
    repostListing 
} from "@/lib/api/user/listings";
import { LISTING_TYPE } from "@shared/enums/listingType";
import { queryKeys } from "@/hooks/queries/queryKeys";
import type { User } from "@/types/User";

export type ProfileListingType = "ads" | "services" | "spare-parts";

export function useProfileListings<T extends { id: unknown; status: string } = any>(
    type: ProfileListingType,
    activeSubTab: string,
    user: User | null,
    statusFilter: ListingStatus = "live"
) {
    const isActive = activeSubTab === type;

    const config: unknown = {
        ads: {
            fetchApi: () => getMyListings(LISTING_TYPE.AD, statusFilter).then(res => res.data),
            deleteApi: (id: string) => deleteListing(id, LISTING_TYPE.AD),
            markSoldApi: markListingAsSold,
            deactivateApi: deactivateListing,
            repostApi: (id: string) => repostListing(id, LISTING_TYPE.AD),
            queryKey: queryKeys.ads.myAds(statusFilter, LISTING_TYPE.AD)
        },
        services: {
            fetchApi: () => getMyListings(LISTING_TYPE.SERVICE, statusFilter).then(res => res.data),
            deleteApi: (id: string) => deleteListing(id, LISTING_TYPE.SERVICE),
            markSoldApi: markListingAsSold,
            deactivateApi: deactivateListing,
            repostApi: (id: string) => repostListing(id, LISTING_TYPE.SERVICE),
            queryKey: queryKeys.ads.myAds(statusFilter, LISTING_TYPE.SERVICE)
        },
        "spare-parts": {
            fetchApi: () => getMyListings(LISTING_TYPE.SPARE_PART, statusFilter).then(res => res.data),
            deleteApi: (id: string) => deleteListing(id, LISTING_TYPE.SPARE_PART),
            markSoldApi: markListingAsSold,
            deactivateApi: deactivateListing,
            repostApi: (id: string) => repostListing(id, LISTING_TYPE.SPARE_PART),
            queryKey: queryKeys.ads.myAds(statusFilter, LISTING_TYPE.SPARE_PART)
        }
    }[type];

    const {
        listings,
        loading,
        error,
        refetch,
        handleDelete,
        handleMarkSold,
        handleDeactivate,
        handleRepost,
    } = useUserListingManagement<T>({
        type: type as unknown,
        activeTab: isActive ? type : "",
        user,
        statusFilter,
        ...config
    });

    return {
        listings,
        loading,
        error,
        refetch,
        handleDelete,
        handleMarkSold,
        handleDeactivate,
        handleRepost,
    };
}

"use client";

import React from "react";
import { UseFormReturn } from "react-hook-form";
import logger from "@/lib/logger";
import { 
    createRemoteListingImages,
} from "./listingFormShared";
import type { ListingImage } from "@/types/listing";
import { useBusiness } from "@/hooks/useBusiness";
import { useAuth } from "@/context/AuthContext";
import { buildGenericListingEditResetValues } from "@/lib/listings/postingFormNormalization";
import { useListingEditPreload } from "./useListingEditPreload";

interface UseGenericListingFormProps<T extends Record<string, any>> {
    form: UseFormReturn<T>;
    editId?: string;
    onDataLoaded?: (payload: unknown) => void;
}

export function useGenericListingForm<T extends Record<string, any>>({
    form,
    editId,
    onDataLoaded,
}: UseGenericListingFormProps<T>) {
    const { user } = useAuth();
    const { businessData } = useBusiness(user, undefined, {
        includeStats: false,
    });
    const [images, setImages] = React.useState<ListingImage[]>([]);
    const { isFetchingData } = useListingEditPreload<Record<string, unknown>>({
        editId,
        onPayload: async (payload) => {
            if (Array.isArray(payload.images) && payload.images.length > 0) {
                setImages(createRemoteListingImages(payload.images));
            }

            if (onDataLoaded) {
                await onDataLoaded(payload);
                return;
            }

            form.reset(buildGenericListingEditResetValues(payload) as unknown);
        },
        onError: (error) => {
            logger.error("Failed to load listing", error);
        },
    });

    return {
        images,
        setImages,
        isFetchingData,
        businessData,
    };
}

