async function runScenarioD() {
    logger.info('[SMOKE_TEST] SCENARIO D: VIEW SYSTEM START');

    const adId = new mongoose.Types.ObjectId();
    await Ad.create({
        _id: adId,
        title: 'View Test Ad',
        description: 'View Test description for the smoke test ad (20+ chars)',
        price: 100,
