/**
 * 🧹 Esparex Orphan Sweep
 * 
 * This script identifies "orphan" files—files that are not imported or referenced
 * by any other file in the repository.
 * 
 * Usage: node scripts/orphan-sweep.cjs
 */

const fs = require('fs');
const path = require('path');
const { execSync } = require('child_process');

const SEARCH_DIRS = ['apps', 'backend', 'core', 'shared'];
const EXTENSIONS = ['.ts', '.tsx', '.js', '.jsx'];

function getAllFiles(dir, allFiles = []) {
    const files = fs.readdirSync(dir);
    files.forEach(file => {
        const name = path.join(dir, file);
        if (fs.statSync(name).isDirectory()) {
            if (file !== 'node_modules' && file !== 'dist' && !file.startsWith('.')) {
                getAllFiles(name, allFiles);
            }
        } else {
            if (EXTENSIONS.includes(path.extname(file))) {
                allFiles.push(name);
            }
        }
    });
    return allFiles;
}

console.log('🔍 Scanning repository for orphan files...');

const allFiles = SEARCH_DIRS.flatMap(dir => {
    const fullPath = path.join(process.cwd(), dir);
    return fs.existsSync(fullPath) ? getAllFiles(fullPath) : [];
});

console.log(`📦 Found ${allFiles.length} source files. Checking references...`);

const orphans = [];

allFiles.forEach((file, index) => {
    const fileName = path.basename(file, path.extname(file));
    const relPath = path.relative(process.cwd(), file);

    // Progress indicator
    if (index % 50 === 0) process.stdout.write('.');

    try {
        // Grep for the filename in the entire repo, excluding itself
        // We look for imports like 'from "filename"' or 'require("filename")'
        const count = execSync(`grep -r "${fileName}" . --exclude="${relPath}" --exclude-dir="node_modules" --exclude-dir="dist" | wc -l`, { encoding: 'utf8' }).trim();

        if (parseInt(count) === 0) {
            orphans.push(relPath);
        }
    } catch (e) {
        // Ignore errors from grep
    }
});

console.log('\n\n--------------------------------------------------');
console.log('🧹 ORPHAN REPORT');
console.log(`Detected ${orphans.length} potentially unused files:`);
console.log('--------------------------------------------------');

orphans.forEach(o => console.log(`[DELETE] ${o}`));

if (orphans.length > 0) {
    console.log('\n⚠️ ACTION REQUIRED: Verify these files are not used dynamically before deletion.');
} else {
    console.log('\n✅ No orphans detected. Repository is lean!');
}

#!/usr/bin/env node

const fs = require("node:fs");
const path = require("node:path");

const repoRoot = path.resolve(__dirname, "..");
const frontendRoutesFile = path.join(repoRoot, "apps/web/src/api/routes.ts");
const backendAppFile = path.join(repoRoot, "backend/user/src/app.ts");

const METHOD_REGEX =
  /\b([A-Za-z_$][A-Za-z0-9_$]*)\.(get|post|put|patch|delete)\(\s*['"`]([^'"`]+)['"`]/g;
const SUBROUTER_REGEX =
  /\b([A-Za-z_$][A-Za-z0-9_$]*)\.use\(\s*['"`]([^'"`]+)['"`]\s*,\s*([A-Za-z_$][A-Za-z0-9_$]*)\s*\)/g;

function read(filePath) {
  return fs.readFileSync(filePath, "utf8");
}

function parseArgs() {
  const scopeArg = process.argv.find((arg) => arg.startsWith("--scope="));
  const scope = scopeArg ? scopeArg.split("=")[1] : "both";
  if (!["user", "admin", "both"].includes(scope)) {
    throw new Error(`Invalid --scope value: ${scope}`);
  }
  return { scope };
}

function extractBlock(source, startMarker, endMarker) {
  const start = source.indexOf(startMarker);
  if (start === -1) {
    throw new Error(`Unable to locate block marker: ${startMarker}`);
  }

  const end = endMarker ? source.indexOf(endMarker, start) : source.lastIndexOf("} as const");
  if (end === -1) {
    throw new Error(`Unable to locate end marker for block: ${startMarker}`);
  }

  return source.slice(start, end);
}

function extractStaticConstants(block) {
  const constants = [];
  const regex = /^\s*([A-Z0-9_]+)\s*:\s*"([^"]+)"\s*,?\s*$/gm;

  let match = regex.exec(block);
  while (match) {
    constants.push({ key: match[1], path: match[2] });
    match = regex.exec(block);
  }

  return constants;
}

function normalizeInterpolatedPath(rawPath) {
  // Replace simple template placeholders with dynamic segment markers
  return rawPath.replace(/\$\{[^{}]*\}/g, ":param");
}

function extractFunctionConstants(block) {
  const constants = [];
  const fnRegex =
    /([A-Z0-9_]+)\s*:\s*\([^)]*\)\s*=>\s*(`[\s\S]*?`|'[^']*'|"[^"]*")\s*,/g;

  let match = fnRegex.exec(block);
  while (match) {
    const key = match[1];
    const rawLiteral = match[2];
    const unwrapped = rawLiteral.slice(1, -1);
    constants.push({ key, path: normalizeInterpolatedPath(unwrapped) });
    match = fnRegex.exec(block);
  }

  return constants;
}

function extractRouteModuleImports(source, relativeToDir) {
  const imports = new Map();
  const importRegex = /import\s+([^;]+?)\s+from\s+['"]([^'"]+)['"]/g;

  let match = importRegex.exec(source);
  while (match) {
    const spec = match[1].trim();
    const importPath = match[2];

    if (!importPath.startsWith("./")) {
      match = importRegex.exec(source);
      continue;
    }

    const resolvedFile = path.resolve(
      relativeToDir,
      importPath.endsWith(".ts") ? importPath : `${importPath}.ts`
    );

    if (spec.startsWith("{")) {
      const named = spec.replace(/^\{|\}$/g, "").split(",");
      for (const item of named) {
        const trimmed = item.trim();
        if (!trimmed) continue;
        const parts = trimmed.split(/\s+as\s+/);
        const localName = (parts[1] || parts[0]).trim();
        imports.set(localName, resolvedFile);
      }
      match = importRegex.exec(source);
      continue;
    }

    const [defaultImport] = spec.split(",");
    if (defaultImport && !defaultImport.includes("{")) {
      imports.set(defaultImport.trim(), resolvedFile);
    }

    const namedMatch = spec.match(/\{([^}]+)\}/);
    if (namedMatch) {
      const named = namedMatch[1].split(",");
      for (const item of named) {
        const trimmed = item.trim();
        if (!trimmed) continue;
        const parts = trimmed.split(/\s+as\s+/);
        const localName = (parts[1] || parts[0]).trim();
        imports.set(localName, resolvedFile);
      }
    }

    match = importRegex.exec(source);
  }

  return imports;
}

function joinPaths(base, segment) {
  const normalizedBase = base === "/" ? "" : base.replace(/\/+$/, "");
  const normalizedSegment = segment === "/" ? "" : segment.replace(/^\/+/, "");
  const joined = `/${[normalizedBase.replace(/^\/+/, ""), normalizedSegment]
    .filter(Boolean)
    .join("/")}`;
  return joined === "" ? "/" : joined;
}

function toRegex(pattern) {
  const escaped = pattern.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
  const withParams = escaped.replace(/:[A-Za-z0-9_]+/g, "[^/]+");
  return new RegExp(`^${withParams}$`);
}

function normalizeRoutePath(routePath, namespace) {
  const [pathOnly] = routePath.split("?");
  const withLeadingSlash = pathOnly.startsWith("/") ? pathOnly : `/${pathOnly}`;
  const normalized = withLeadingSlash.replace(/\/+$/, "") || "/";

  if (namespace === "user") {
    return normalized;
  }
  return normalized;
}

function collectPatternsFromRouteFile(routeFilePath, mountPrefix, visited) {
  const key = `${routeFilePath}::${mountPrefix}`;
  if (visited.has(key)) return [];
  visited.add(key);

  if (!fs.existsSync(routeFilePath)) return [];

  const source = read(routeFilePath);
  const fileDir = path.dirname(routeFilePath);
  const imports = extractRouteModuleImports(source, fileDir);

  const patterns = [{ method: "ANY", pattern: mountPrefix }];

  let methodMatch = METHOD_REGEX.exec(source);
  while (methodMatch) {
    const routePath = methodMatch[3];
    patterns.push({
      method: methodMatch[2].toUpperCase(),
      pattern: routePath === "/" ? mountPrefix : joinPaths(mountPrefix, routePath),
    });
    methodMatch = METHOD_REGEX.exec(source);
  }
  METHOD_REGEX.lastIndex = 0;

  let subrouterMatch = SUBROUTER_REGEX.exec(source);
  while (subrouterMatch) {
    const childMountPath = subrouterMatch[2];
    const childModule = subrouterMatch[3];
    const childFile = imports.get(childModule);

    if (childFile) {
      const childPrefix =
        childMountPath === "/" ? mountPrefix : joinPaths(mountPrefix, childMountPath);
      patterns.push(
        ...collectPatternsFromRouteFile(childFile, childPrefix, visited)
      );
    }

    subrouterMatch = SUBROUTER_REGEX.exec(source);
  }
  SUBROUTER_REGEX.lastIndex = 0;

  return patterns;
}

function extractMountedPatterns(appSource, namespaceBase) {
  const appDir = path.dirname(backendAppFile);
  const imports = extractRouteModuleImports(appSource, appDir);

  const mountRegex =
    /app\.use\(\s*['"]([^'"]+)['"]\s*,\s*([A-Za-z_$][A-Za-z0-9_$]*)\s*\)/g;
  const mounts = [];

  let match = mountRegex.exec(appSource);
  while (match) {
    const mountedPath = match[1];
    const moduleName = match[2];

    if (!mountedPath.startsWith(namespaceBase)) {
      match = mountRegex.exec(appSource);
      continue;
    }

    const localPrefix = mountedPath.slice(namespaceBase.length) || "/";
    const routeFilePath = imports.get(moduleName);
    if (routeFilePath) {
      mounts.push({ localPrefix, routeFilePath });
    }

    match = mountRegex.exec(appSource);
  }

  const patterns = [];
  const visited = new Set();
  for (const mount of mounts) {
    patterns.push(
      ...collectPatternsFromRouteFile(mount.routeFilePath, normalizeRoutePath(mount.localPrefix), visited)
    );
  }

  return patterns.map((entry) => ({ ...entry, regex: toRegex(entry.pattern) }));
}

function checkScope(groupName, constants, backendPatterns) {
  const failures = [];

  for (const constant of constants) {
    const normalizedPath = normalizeRoutePath(constant.path);
    const matched = backendPatterns.some((pattern) =>
      pattern.regex.test(normalizedPath)
    );

    if (!matched) {
      failures.push({
        key: constant.key,
        rawPath: constant.path,
        normalizedPath,
      });
    }
  }

  return {
    groupName,
    checked: constants.length,
    failures,
  };
}

function printReport(reports) {
  let hasFailures = false;

  for (const report of reports) {
    if (report.failures.length > 0) {
      hasFailures = true;
      console.error(`❌ ${report.groupName} API contract drift detected.`);
      for (const failure of report.failures) {
        console.error(
          ` - API_ROUTES.${report.groupName}.${failure.key} = "${failure.rawPath}" (normalized: ${failure.normalizedPath}) is not mounted in backend`
        );
      }
      console.error(
        `Checked ${report.checked} ${report.groupName} route keys, failed ${report.failures.length}.`
      );
      console.error(`\n[HINT] The frontend ${report.groupName}_ROUTES constant has drifted from the backend implementation.`);
      console.error("1. Check if the route is actually mounted in 'backend/user/src/app.ts' or relevant sub-routers.");
      console.error("2. Ensure the path string in the frontend contract exactly matches the backend path.");
      console.error("3. If this is a new route, verify it is properly versioned under /api/v1/.\n");
    } else {
      console.log(
        `✅ ${report.groupName} API contract check passed. Checked ${report.checked} ${report.groupName} route keys.`
      );
    }
  }

  if (hasFailures) {
    process.exit(1);
  }
}

function main() {
  const { scope } = parseArgs();

  const appSource = read(backendAppFile);

  // SSOT: Routes are now managed in the shared module
  const userSource = read(path.join(repoRoot, "shared/contracts/api/userRoutes.ts"));
  const adminSource = read(path.join(repoRoot, "shared/contracts/api/adminRoutes.ts"));

  const userBlock = extractBlock(userSource, "export const USER_ROUTES = {", "} as const;");
  const adminBlock = extractBlock(adminSource, "export const ADMIN_ROUTES = {", "} as const;");

  const userConstants = [
    ...extractStaticConstants(userBlock),
    ...extractFunctionConstants(userBlock),
  ];
  const adminConstants = [
    ...extractStaticConstants(adminBlock),
    ...extractFunctionConstants(adminBlock),
  ];

  const userPatterns = extractMountedPatterns(appSource, "/api/v1");
  const adminPatterns = extractMountedPatterns(appSource, "/api/v1/admin");

  const reports = [];

  if (scope === "user" || scope === "both") {
    reports.push(checkScope("USER", userConstants, userPatterns));
  }
  if (scope === "admin" || scope === "both") {
    reports.push(checkScope("ADMIN", adminConstants, adminPatterns));
  }

  printReport(reports);
}

main();

import type { Logger, LogDetails, LogLevel } from './types';

/**
 * Universal Logger implementation that works in both Node and Browser.
 */
class UniversalLogger implements Logger {
    public level: LogLevel = 'info';

    constructor(
        private prefix: string = '',
        private defaultMeta: LogDetails = {}
    ) {}

    private serializeValue(value: unknown, seen = new WeakSet<object>()): unknown {
        if (value instanceof Error) {
            const serialized: Record<string, unknown> = {
                name: value.name,
                message: value.message,
            };

            if (value.stack) serialized.stack = value.stack;

            for (const [key, nestedValue] of Object.entries(value as unknown as Record<string, unknown>)) {
                if (!(key in serialized)) {
                    serialized[key] = this.serializeValue(nestedValue, seen);
                }
            }

            return serialized;
        }

        if (value instanceof Date) {
            return value.toISOString();
        }

        if (typeof value === 'bigint') {
            return value.toString();
        }

        if (Array.isArray(value)) {
            return value.map((entry) => this.serializeValue(entry, seen));
        }

        if (value && typeof value === 'object') {
            if (seen.has(value)) {
                return '[Circular]';
            }

            seen.add(value);

            try {
                const candidate = value as { toJSON?: () => unknown };
                if (typeof candidate.toJSON === 'function') {
                    const serialized = candidate.toJSON();
                    if (serialized !== value) {
                        return this.serializeValue(serialized, seen);
                    }
                }
            } catch {
                // Fall through to plain object serialization.
            }

            const serialized: Record<string, unknown> = {};
            for (const [key, nestedValue] of Object.entries(value as Record<string, unknown>)) {
                serialized[key] = this.serializeValue(nestedValue, seen);
            }
            return serialized;
        }

        return value;
    }

    private safeStringify(value: unknown): string {
        try {
            return JSON.stringify(this.serializeValue(value));
        } catch {
            return String(value);
        }
    }

    private format(message: unknown, ...meta: unknown[]): string {
        const defaultMeta = { ...this.defaultMeta };
        let msgStr = '';
        if (message instanceof Error) {
            msgStr = message.stack || message.message;
            const serialized = this.serializeValue(message) as Record<string, unknown>;
            const extraEntries = Object.entries(serialized).filter(([key]) => !['name', 'message', 'stack'].includes(key));
            if (extraEntries.length > 0) {
                msgStr += ` ${this.safeStringify(Object.fromEntries(extraEntries))}`;
            }
        } else if (typeof message === 'object') {
            msgStr = this.safeStringify(message);
        } else {
            msgStr = String(message);
        }

        let metaStr = '';
        if (meta.length > 0) {
            metaStr = ` ${this.safeStringify(meta)}`;
        }
        const defaultMetaStr = Object.keys(defaultMeta).length > 0 ? ` ${this.safeStringify(defaultMeta)}` : '';
        return `${this.prefix}${msgStr}${metaStr}${defaultMetaStr}`;
    }

    public log(level: LogLevel, message: unknown, ...meta: unknown[]): void {
        const formatted = this.format(message, ...meta);
        switch (level) {
            case 'debug': console.debug(formatted); break;
            case 'info': console.info(formatted); break;
            case 'warn':
            case 'warning': console.warn(formatted); break;
            case 'error': console.error(formatted); break;
            case 'http': console.log(`[HTTP] ${formatted}`); break;
        }
    }

    debug(message: unknown, ...meta: unknown[]): void { this.log('debug', message, ...meta); }
    info(message: unknown, ...meta: unknown[]): void { this.log('info', message, ...meta); }
    warn(message: unknown, ...meta: unknown[]): void { this.log('warn', message, ...meta); }
    warning(message: unknown, ...meta: unknown[]): void { this.log('warning', message, ...meta); }
    error(message: unknown, ...meta: unknown[]): void { this.log('error', message, ...meta); }
    http(message: unknown, ...meta: unknown[]): void { this.log('http', message, ...meta); }

    child(defaultMeta: LogDetails): Logger {
        return new UniversalLogger(this.prefix, { ...this.defaultMeta, ...defaultMeta });
    }
}

export const createUniversalLogger = (serviceName: string): Logger => {
    return new UniversalLogger(`[${serviceName}] `);
};

import { z } from 'zod';
import { objectIdSchema } from './common.schemas';
import { coordinatesSchema } from './coordinates.schema';

const optionalTrimmedString = z.preprocess(
    (value) => {
        if (typeof value !== 'string') return value;
        const trimmed = value.trim();
        return trimmed.length > 0 ? trimmed : undefined;
    },
    z.string().optional()
);

const frequencySchema = z.enum(['daily', 'instant']);
const notificationChannelSchema = z.enum(['email', 'sms', 'push']);

const smartAlertCriteriaSchema = z
    .object({
        keywords: optionalTrimmedString,
        category: optionalTrimmedString,
        brand: optionalTrimmedString,
        model: optionalTrimmedString,
        categoryId: objectIdSchema.optional(),
        brandId: objectIdSchema.optional(),
        modelId: objectIdSchema.optional(),
        minPrice: z.coerce.number().min(0).optional(),
        maxPrice: z.coerce.number().min(0).optional(),
        condition: optionalTrimmedString,
        location: optionalTrimmedString,
        locationId: objectIdSchema.optional(),
        state: optionalTrimmedString,
        coordinates: coordinatesSchema.optional(),
    })
    .superRefine((data, ctx) => {
        if (
            typeof data.minPrice === 'number' &&
            typeof data.maxPrice === 'number' &&
            data.maxPrice < data.minPrice
        ) {
            ctx.addIssue({
                path: ['maxPrice'],
                code: z.ZodIssueCode.custom,
                message: 'Maximum price must be greater than minimum price',
            });
        }
    });

const smartAlertBodySchema = z
    .object({
        alertName: optionalTrimmedString,
        name: optionalTrimmedString,
        criteria: smartAlertCriteriaSchema.optional(),
        frequency: frequencySchema.optional(),
        coordinates: coordinatesSchema.optional(),
        radiusKm: z.coerce.number().min(1).max(500).optional(),
        notificationChannels: z.array(notificationChannelSchema).min(1).max(3).optional(),
    })
    .strict();

const normalizeSmartAlertBody = (
    data: z.infer<typeof smartAlertBodySchema>,
    options: { applyFrequencyDefault: boolean }
) => {
    const normalizedName = data.name ?? data.alertName;
    const { alertName: _alertName, ...rest } = data;
    return {
        ...rest,
        name: normalizedName,
        ...(options.applyFrequencyDefault ? { frequency: data.frequency ?? 'instant' } : {}),
    };
};

export const SmartAlertCreateSchema = smartAlertBodySchema
    .superRefine((data, ctx) => {
        const candidateName = data.name ?? data.alertName;
        if (!candidateName) {
            ctx.addIssue({
                path: ['name'],
                code: z.ZodIssueCode.custom,
                message: 'Alert name is required',
            });
            return;
        }
        if (candidateName.length < 3 || candidateName.length > 50) {
            ctx.addIssue({
                path: ['name'],
                code: z.ZodIssueCode.custom,
                message: 'Alert name must be between 3 and 50 characters',
            });
        }

        if (!data.criteria || typeof data.criteria !== 'object') {
            ctx.addIssue({
                path: ['criteria'],
                code: z.ZodIssueCode.custom,
                message: 'Alert criteria is required',
            });
        }
    })
    .transform((data) => normalizeSmartAlertBody(data, { applyFrequencyDefault: true }));

export const SmartAlertUpdateSchema = smartAlertBodySchema
    .superRefine((data, ctx) => {
        if (Object.keys(data).length === 0) {
            ctx.addIssue({
                path: ['_root'],
                code: z.ZodIssueCode.custom,
                message: 'At least one field is required to update alert',
            });
            return;
        }

        const candidateName = data.name ?? data.alertName;
        if (candidateName && (candidateName.length < 3 || candidateName.length > 50)) {
            ctx.addIssue({
                path: ['name'],
                code: z.ZodIssueCode.custom,
                message: 'Alert name must be between 3 and 50 characters',
            });
        }
    })
    .transform((data) => normalizeSmartAlertBody(data, { applyFrequencyDefault: false }));

export type SmartAlertCreatePayload = z.infer<typeof SmartAlertCreateSchema>;
export type SmartAlertUpdatePayload = z.infer<typeof SmartAlertUpdateSchema>;

export const SmartAlertDeliveryLogSchema = z.object({
    _id: z.string(),
    alertId: z.union([
        z.string(),
        z.object({
            _id: z.string(),
            name: z.string(),
            criteria: z.record(z.string(), z.any()),
            user: z.string().optional()
        })
    ]),
    adId: z.union([
        z.string(),
        z.object({
            _id: z.string(),
            title: z.string(),
            price: z.number(),
            location: z.string().optional(),
            status: z.string()
        })
    ]),
    deliveredAt: z.union([z.string(), z.date()]),
    userName: z.string().optional(),
    userEmail: z.string().optional(),
    adTitle: z.string().optional()
});

export type SmartAlertDeliveryLogDTO = z.infer<typeof SmartAlertDeliveryLogSchema>;
